function ensureDir(dirPath) { try { if (!fsSync.existsSync(dirPath)) fsSync.mkdirSync(dirPath, { recursive: true }); } catch(e) {} }

function readJsonConfig(filePath, defaults) {
    try {
        if (fsSync.existsSync(filePath)) {
            const data = JSON.parse(fsSync.readFileSync(filePath, 'utf8'));
            return Object.assign(defaults || {}, data);
        }
    } catch(e) {}
    return defaults || {};
}

function timeToMs(s, m, h, d) {
    return ((parseInt(s)||0) + (parseInt(m)||0)*60 + (parseInt(h)||0)*3600 + (parseInt(d)||0)*86400) * 1000;
}

function formatDuration(ms, showSeconds) {
    if (!ms || ms <= 0) return showSeconds ? '0秒' : '0分钟';
    const days = Math.floor(ms / 86400000);
    const hours = Math.floor((ms % 86400000) / 3600000);
    const minutes = Math.floor((ms % 3600000) / 60000);
    const seconds = Math.floor((ms % 60000) / 1000);
    const parts = [];
    if (days > 0) parts.push(days + '天');
    if (hours > 0) parts.push(hours + '小时');
    if (minutes > 0) parts.push(minutes + '分钟');
    if (showSeconds !== false && seconds > 0) parts.push(seconds + '秒');
    return parts.join('') || (showSeconds ? '0秒' : '0分钟');
}
function formatDurationMinutes(totalMinutes) {
    totalMinutes = parseInt(totalMinutes) || 0;
    if (totalMinutes <= 0) return '0分钟';
    const days = Math.floor(totalMinutes / 1440);
    const hours = Math.floor((totalMinutes % 1440) / 60);
    const mins = totalMinutes % 60;
    const parts = [];
    if (days > 0) parts.push(days + '天');
    if (hours > 0) parts.push(hours + '小时');
    if (mins > 0) parts.push(mins + '分钟');
    return parts.join('') || '0分钟';
}

async function undiciAdapter(config) {
    const urlObj = new URL(config.url, config.baseURL);
    if (config.params) {
        Object.keys(config.params).forEach(key =>
            urlObj.searchParams.append(key, config.params[key])
        );
    }
    const controller = new AbortController();
    const timeout = config.timeout || 5000;
    const timer = setTimeout(() => controller.abort(), timeout);
    const options = {
        method: config.method || 'GET',
        headers: config.headers || {},
        body: config.data ? (typeof config.data === 'object' ? JSON.stringify(config.data) : config.data) : undefined,
        signal: controller.signal
    };
    if (config.data && typeof config.data === 'object' && !options.headers['Content-Type']) {
        options.headers['Content-Type'] = 'application/json';
    }
    try {
        const response = await fetch(urlObj.toString(), options);
        clearTimeout(timer);
        let data;
        const contentType = response.headers.get('content-type') || '';
        if (contentType.includes('application/json')) {
            data = await response.json();
        } else {
            data = await response.text();
        }
        const result = {
            data: data,
            status: response.status,
            statusText: response.statusText,
            headers: response.headers,
            config: config
        };
        const validateStatus = config.validateStatus || ((status) => status >= 200 && status < 300);
        if (!validateStatus(response.status)) {
            const error = new Error(`Request failed with status code ${response.status}`);
            error.response = result;
            throw error;
        }
        return result;
    } catch (err) {
        clearTimeout(timer);
        throw err;
    }
}
const axios = new Proxy(nativeAxios, {
    apply: async function(target, thisArg, args) {
        const config = args[0];
        try {
            return await target(config);
        } catch (error) {
            const shouldSwitch = error.code === 'ECONNABORTED' ||
                                 error.message.includes('timeout') ||
                                 error.code === 'ECONNREFUSED' ||
                                 error.code === 'ENOTFOUND';
            if (shouldSwitch) {
                try {
                    return await undiciAdapter(config);
                } catch (fallbackError) {
                    throw fallbackError;
                }
            }
            throw error;
        }
    },
    get: function(target, prop) {
        if (prop === 'get') return (url, config = {}) => axios({ ...config, method: 'GET', url });
        if (prop === 'post') return (url, data, config = {}) => axios({ ...config, method: 'POST', url, data });
        if (prop === 'put') return (url, data, config = {}) => axios({ ...config, method: 'PUT', url, data });
        if (prop === 'delete') return (url, config = {}) => axios({ ...config, method: 'DELETE', url });
        if (prop === 'patch') return (url, data, config = {}) => axios({ ...config, method: 'PATCH', url, data });
        if (prop === 'head') return (url, config = {}) => axios({ ...config, method: 'HEAD', url });
        if (prop === 'options') return (url, config = {}) => axios({ ...config, method: 'OPTIONS', url });
        return target[prop];
    }
});
async function sendDiscordMessage(taskConfig, message) {
    const { discordWebhookUrl, discordSelfBotToken, discordChannelId, discordSelfBotMode = false } = taskConfig;
    try {
        if (discordSelfBotMode && discordSelfBotToken && discordChannelId) {
            const url = `https://discord.com/api/v9/channels/${discordChannelId}/messages`;
            const response = await axios.post(url, {
                content: message,
                tts: false,
                flags: 0
            }, {
                headers: {
                    'Authorization': discordSelfBotToken,
                    'User-Agent': COMMON_BROWSER_UA,
                    'Content-Type': 'application/json'
                },
                timeout: 10000
            });
            return {
                success: true,
                message: 'Discord 消息发送成功',
                data: response.data
            };
        } else if (discordWebhookUrl) {
            const response = await axios.post(discordWebhookUrl, {
                content: message,
                username: taskConfig.discordUsername || 'Pathfinder Pro',
                avatar_url: taskConfig.discordAvatarUrl || '',
                tts: false
            }, {
                headers: {
                    'Content-Type': 'application/json'
                },
                timeout: 10000
            });
            return {
                success: true,
                message: 'Discord 消息发送成功',
                data: response.data
            };
        } else {
            return {
                success: false,
                message: 'Discord 配置不完整'
            };
        }
    } catch (error) {
        return {
            success: false,
            message: `Discord 消息发送失败: ${error.message}`
        };
    }
}

const REFERRAL_ADJECTIVES = ['swift','cool','dark','wild','fast','keen','bold','wise','calm','pure','rare','true','free','warm','nice','safe','fair','real','good','fine','epic','lucky','tiny','mega','ultra','neo','pro','cyber','hyper','solo','alpha'];
const REFERRAL_NOUNS = ['wolf','hawk','bear','lion','fox','deer','star','moon','wind','fire','ice','rock','lake','peak','wave','storm','raven','eagle','cobra','lynx','panda','otter','frost','blade','ghost','spark','shadow','nova','flux','echo'];
const REFERRAL_ADJECTIVES_EXTRA = REFERRAL_ADJECTIVES.concat(['icy','red','blue','gray','old','big','sly','fly','dry']);
const REFERRAL_NOUNS_EXTRA = REFERRAL_NOUNS.concat(['atlas','cedar','dusk','ember','fjord','grove','haze','jade','kite','opal']);
const REFERRAL_NOUNS_GAME = ['wolf','hawk','bear','lion','fox','star','moon','wind','fire','ice','rock','storm','raven','eagle','cobra','ghost','spark','shadow','nova','frost'];
const REFERRAL_DIGITS = '0123456789';
function referralRandomChoice(arr) { return arr[Math.floor(Math.random() * arr.length)]; }
function referralRandomDigits(n) { return Array.from({length: n}, () => REFERRAL_DIGITS[Math.floor(Math.random() * REFERRAL_DIGITS.length)]).join(''); }
function referralRandomHex(n) { return crypto.randomBytes(Math.ceil(n/2)).toString('hex').slice(0, n); }

function generateReferralUsername() {
    const styles = [
        () => {
            return referralRandomChoice(REFERRAL_ADJECTIVES) + referralRandomChoice(REFERRAL_NOUNS);
        },
        () => {
            return referralRandomChoice(REFERRAL_ADJECTIVES_EXTRA) + '_' + referralRandomChoice(REFERRAL_NOUNS) + '_' + referralRandomDigits(Math.random() < 0.5 ? 1 : 2);
        },
        () => {
            const first = ['james','alex','sam','jordan','taylor','morgan','casey','riley','avery','quinn','blake','cameron','drew','ethan','finn','grace','harper','iris','jack','kai','luna','milo','noah','olive','piper','rowan','sage','tyler','vera','zoe'];
            const initials = 'abcdefghijklmnopqrstuvwxyz';
            return referralRandomChoice(first) + initials[Math.floor(Math.random() * initials.length)] + referralRandomDigits(Math.random() < 0.6 ? 2 : 3);
        },
        () => {
            return referralRandomChoice(REFERRAL_NOUNS_EXTRA) + referralRandomDigits(Math.random() < 0.4 ? 2 : 3);
        },
        () => {
            const initials = 'abcdefghijklmnopqrstuvwxyz';
            const c = () => initials[Math.floor(Math.random() * initials.length)];
            const d = () => referralRandomDigits(Math.random() < 0.5 ? 2 : 3);
            return c() + c() + '_' + d() + c();
        },
        () => {
            const surnames = ['wang','li','zhang','liu','chen','yang','zhao','huang','zhou','wu','xu','sun','ma','zhu','hu','guo','lin','he','gao','luo'];
            const names = ['ming','wei','hao','jun','jie','yu','xin','chen','rui','bo','tao','lei','peng','fei','yan','ling','yun','kai','sheng','da'];
            return referralRandomChoice(surnames) + referralRandomChoice(names) + referralRandomDigits(Math.random() < 0.5 ? 2 : 3);
        },
        () => {
            const c = () => 'abcdefghijklmnopqrstuvwxyz'[Math.floor(Math.random() * 26)];
            const len = Math.random() < 0.5 ? 2 : 3;
            let s = '';
            for (let i = 0; i < len; i++) s += c();
            s += referralRandomDigits(Math.random() < 0.4 ? 3 : 4);
            return s;
        },
        () => {
            const n = referralRandomChoice(REFERRAL_NOUNS_GAME);
            const wrappers = [
                'xX' + n.charAt(0).toUpperCase() + n.slice(1) + 'Xx',
                n + '-' + referralRandomDigits(2),
                '_' + n + '_',
                n + '.' + referralRandomDigits(3),
                'Itz' + n.charAt(0).toUpperCase() + n.slice(1),
            ];
            return referralRandomChoice(wrappers);
        },
    ];
    const style = styles[Math.floor(Math.random() * styles.length)];
    return style();
}

function generateReferralPassword() {
    const upper = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
    const lower = 'abcdefghijklmnopqrstuvwxyz';
    const nums = '0123456789';
    const special = '!@#$%';
    const all = upper + lower + nums + special;
    let pw = '';
    pw += upper[Math.floor(Math.random() * upper.length)];
    pw += lower[Math.floor(Math.random() * lower.length)];
    pw += nums[Math.floor(Math.random() * nums.length)];
    pw += special[Math.floor(Math.random() * special.length)];
    for (let i = 0; i < 10; i++) pw += all[Math.floor(Math.random() * all.length)];
    return pw.split('').sort(() => Math.random() - 0.5).join('');
}

