function generateVektalFingerprint() {
    const bytes = crypto.randomBytes(18);
    return 'vn2_' + Array.from(bytes).map(b => b.toString(16).padStart(2, '0')).join('');
}

function generateVektalFingerprintHint(ua) {
    const parts = ua.match(/Mozilla\/5\.0 \(([^)]+)\)/);
    const platform = parts ? parts[1].split(';').map(s=>s.trim()).pop() || 'Win32' : 'Win32';
    const langs = ['en-US','en-GB','en-AU','en-CA','de-DE','fr-FR','es-ES','pt-BR','ja-JP','ko-KR'];
    const lang = langs[Math.floor(Math.random() * langs.length)];
    const cores = [2,4,6,8,12,16];
    const core = cores[Math.floor(Math.random() * cores.length)];
    const screens = [[1920,1080],[1366,768],[1536,864],[1440,900],[1280,720],[2560,1440]];
    const scr = screens[Math.floor(Math.random() * screens.length)];
    return `${ua}|${lang}|${platform}|${core}|${core}|${scr[0]}|${scr[1]}|24|1|UTC`;
}

function referralExtractCookies(headers) {
    const setCookies = headers['set-cookie'];
    if (!setCookies) return '';
    return setCookies.map(c => c.split(';')[0]).join('; ');
}

function mergeCookies(oldCookieStr, newCookieStr) {
    const parseCookie = (str) => {
        const obj = {};
        if (!str) return obj;
        str.split(';').forEach(pair => {
            const [key, ...vals] = pair.trim().split('=');
            if (key) obj[key.trim()] = vals.join('=').trim();
        });
        return obj;
    };
    const oldObj = parseCookie(oldCookieStr);
    const newObj = parseCookie(newCookieStr);
    const merged = { ...oldObj, ...newObj };
    return Object.entries(merged).map(([k, v]) => `${k}=${v}`).join('; ');
}

const _net = require('net');
const _tls = require('tls');

function referralSocks5Connect(proxyHost, proxyPort, targetHost, targetPort) {
    return new Promise((resolve, reject) => {
        const socket = new _net.Socket();
        let step = 0;
        const timer = setTimeout(() => { socket.destroy(); reject(new Error('SOCKS5 timeout')); }, 6000);
        socket.connect(proxyPort, proxyHost, () => {
            socket.write(Buffer.from([0x05, 0x01, 0x00]));
        });
        socket.on('data', (data) => {
            if (step === 0) {
                if (data.length < 2 || data[0] !== 0x05 || data[1] !== 0x00) {
                    clearTimeout(timer); socket.destroy(); reject(new Error('SOCKS5 auth failed')); return;
                }
                step = 1;
                const hostBuf = Buffer.from(targetHost);
                const req = Buffer.alloc(7 + hostBuf.length);
                req[0] = 0x05; req[1] = 0x01; req[2] = 0x00; req[3] = 0x03;
                req[4] = hostBuf.length;
                hostBuf.copy(req, 5);
                req.writeUInt16BE(targetPort, 5 + hostBuf.length);
                socket.write(req);
            } else {
                clearTimeout(timer);
                if (data.length < 2 || data[1] !== 0x00) {
                    socket.destroy(); reject(new Error('SOCKS5 connect rejected')); return;
                }
                socket.removeAllListeners('data'); socket.removeAllListeners('error');
                resolve(socket);
            }
        });
        socket.on('error', (err) => { clearTimeout(timer); reject(err); });
    });
}

function referralHttpProxyConnect(proxyHost, proxyPort, targetHost, targetPort) {
    return new Promise((resolve, reject) => {
        const socket = new _net.Socket();
        const timer = setTimeout(() => { socket.destroy(); reject(new Error('HTTP proxy timeout')); }, 6000);
        socket.connect(proxyPort, proxyHost, () => {
            socket.write(`CONNECT ${targetHost}:${targetPort} HTTP/1.1\r\nHost: ${targetHost}:${targetPort}\r\n\r\n`);
        });
        let buf = '';
        socket.on('data', (data) => {
            buf += data.toString();
            if (buf.includes('\r\n\r\n')) {
                clearTimeout(timer);
                if (buf.includes('200')) {
                    socket.removeAllListeners('data'); socket.removeAllListeners('error');
                    resolve(socket);
                } else {
                    socket.destroy(); reject(new Error('HTTP proxy CONNECT failed'));
                }
            }
        });
        socket.on('error', (err) => { clearTimeout(timer); reject(err); });
    });
}

async function referralProxyConnect(proxyUrl, targetHost, targetPort) {
    const proxy = new URL(proxyUrl);
    const pHost = proxy.hostname;
    const pPort = parseInt(proxy.port) || (proxy.protocol.startsWith('socks') ? 1080 : 8080);
    if (proxy.protocol === 'socks5:' || proxy.protocol === 'socks5h:') {
        return referralSocks5Connect(pHost, pPort, targetHost, targetPort);
    }
    return referralHttpProxyConnect(pHost, pPort, targetHost, targetPort);
}

const referralProxyPool = {
    proxies: [],
    working: [],
    lastFetch: 0,
    fetchInterval: timeToMs(0, 5),
    fetching: false,
    validating: false,

    async fetchProxies() {
        if (this.fetching) return this.proxies.length;
        this.fetching = true;
        const sources = [
            { url: 'https://api.proxyscrape.com/v2/?request=displayproxies&protocol=http&timeout=5000&country=all&ssl=all&anonymity=all', type: 'http' },
            { url: 'https://api.proxyscrape.com/v2/?request=displayproxies&protocol=socks5&timeout=5000&country=all', type: 'socks5' },
            { url: 'https://api.proxyscrape.com/v3/free-proxy-list/get?request=displayproxies&protocol=http&timeout=5000', type: 'http' },
            { url: 'https://api.proxyscrape.com/v3/free-proxy-list/get?request=displayproxies&protocol=socks5&timeout=5000', type: 'socks5' },
            { url: 'https://raw.githubusercontent.com/TheSpeedX/PROXY-List/master/http.txt', type: 'http' },
            { url: 'https://raw.githubusercontent.com/TheSpeedX/PROXY-List/master/socks5.txt', type: 'socks5' },
            { url: 'https://raw.githubusercontent.com/monosans/proxy-list/main/proxies/http.txt', type: 'http' },
            { url: 'https://raw.githubusercontent.com/monosans/proxy-list/main/proxies/socks5.txt', type: 'socks5' },
            { url: 'https://raw.githubusercontent.com/hookzof/socks5_list/master/proxy.txt', type: 'socks5' },
            { url: 'https://raw.githubusercontent.com/clarketm/proxy-list/master/proxy-list-raw.txt', type: 'http' },
        ];
        const allProxies = new Set(this.proxies.map(p => p.url));
        for (const src of sources) {
            try {
                const res = await referralMakeRequestDirect(src.url, { timeout: 15000 });
                if (res.status === 200 && res.body) {
                    const lines = res.body.trim().split('\n');
                    for (const line of lines) {
                        const trimmed = line.trim();
                        if (trimmed && trimmed.includes(':')) {
                            const parts = trimmed.split(':');
                            if (parts.length >= 2 && parts[0] && parts[1]) {
                                const port = parseInt(parts[1]);
                                if (port > 0 && port < 65536) {
                                    allProxies.add(`${src.type}://${parts[0]}:${port}`);
                                }
                            }
                        }
                    }
                }
            } catch (e) {}
        }
        this.proxies = [...allProxies].map(url => ({ url, fails: 0 }));
        this.lastFetch = Date.now();
        this.fetching = false;
        return this.proxies.length;
    },

    async validateBatch(batch, testHost) {
        const results = [];
        const concurrency = 20;
        for (let i = 0; i < batch.length; i += concurrency) {
            const chunk = batch.slice(i, i + concurrency);
            const checks = chunk.map(async (proxy) => {
                try {
                    const proxyUrl = typeof proxy === 'string' ? proxy : proxy.url;
                    const socket = await Promise.race([
                        referralProxyConnect(proxyUrl, testHost, 443),
                        new Promise((_, rej) => setTimeout(() => rej(new Error('timeout')), 5000))
                    ]);
                    socket.destroy();
                    return proxyUrl;
                } catch (e) {
                    return null;
                }
            });
            const chunkResults = await Promise.all(checks);
            results.push(...chunkResults.filter(Boolean));
        }
        return results;
    },

    async validatePool(testHost) {
        if (this.validating) return this.working.length;
        this.validating = true;
        const host = testHost || 'vektalnodes.in';
        const batchSize = Math.min(this.proxies.length, 50);
        const batch = this.proxies.slice(0, batchSize);
        const validUrls = await this.validateBatch(batch, host);
        const existingUrls = new Set(this.working.map(p => p.url));
        const newWorking = validUrls.filter(u => !existingUrls.has(u)).map(url => ({ url, fails: 0 }));
        this.working = [...this.working.filter(p => validUrls.includes(p.url)), ...newWorking];
        this.validating = false;
        return this.working.length;
    },

    getRandom() {
        if (this.working.length === 0) return null;
        return this.working[Math.floor(Math.random() * this.working.length)];
    },

    markFail(proxyUrl, permanent) {
        const entry = this.working.find(p => p.url === proxyUrl);
        if (entry) {
            entry.fails++;
            if (permanent || entry.fails >= 3) {
                this.working = this.working.filter(p => p.url !== proxyUrl);
                this.proxies = this.proxies.filter(p => p.url !== proxyUrl);
            }
        }
    },

    markSuccess(proxyUrl) {
        const entry = this.working.find(p => p.url === proxyUrl);
        if (entry) entry.fails = 0;
    },

    async ensurePool(testHost) {
        const needFetch = this.proxies.length === 0 || Date.now() - this.lastFetch > this.fetchInterval;
        const needValidate = this.working.length < 3;
        if (needFetch) await this.fetchProxies();
        if (needValidate || needFetch) await this.validatePool(testHost);
        if (this.working.length < 3 && this.proxies.length > 0) {
            const remaining = this.proxies.filter(p => !this.working.some(w => w.url === p.url));
            if (remaining.length > 0) {
                const extraBatch = remaining.slice(0, 80);
                const extraValid = await this.validateBatch(extraBatch, testHost);
                const newWorking = extraValid.filter(u => !this.working.some(w => w.url === u)).map(url => ({ url, fails: 0 }));
                this.working.push(...newWorking);
            }
        }
        return this.working.length;
    },

    async quickStart(testHost) {
        if (this.working.length >= 3) return this.working.length;
        await this.fetchProxies();
        const quickBatch = this.proxies.slice(0, 50);
        const quickValid = await this.validateBatch(quickBatch, testHost);
        this.working = quickValid.map(url => ({ url, fails: 0 }));
        this._bgValidate(testHost);
        return this.working.length;
    },

    _bgValidate(testHost) {
        if (this._bgRunning) return;
        this._bgRunning = true;
        const remaining = this.proxies.filter(p => !this.working.some(w => w.url === p.url));
        if (remaining.length === 0) { this._bgRunning = false; return; }
        const batch = remaining.slice(0, 100);
        this.validateBatch(batch, testHost).then(validUrls => {
            const existing = new Set(this.working.map(p => p.url));
            const newWorking = validUrls.filter(u => !existing.has(u)).map(url => ({ url, fails: 0 }));
            this.working.push(...newWorking);
            this._bgRunning = false;
            if (this.working.length < 10) this._bgValidate(testHost);
        }).catch(() => { this._bgRunning = false; });
    }
};

async function referralPrescreenProxy(baseUrl, proxyUrl) {
    try {
        const testUrl = `${baseUrl}/register`;
        const UA = referralRandomUA();
        const res = await referralMakeRequest(testUrl, {
            proxy: proxyUrl,
            headers: {
                'User-Agent': UA,
                'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
                'Accept-Language': 'en-US,en;q=0.9',
                'Accept-Encoding': 'gzip, deflate, br',
            },
            timeout: 10000,
        });
        if (res.status === 429) return '429';
        if (res.status === 503 && res.body && res.body.includes('cf-challenge')) return 'cloudflare';
        if (res.status !== 200) return `http_${res.status}`;
        return 'ok';
    } catch(e) {
        return e.message.includes('timeout') ? 'timeout' : 'error';
    }
}

function httpDecompress(buf, encoding, callback) {
    if (encoding === 'gzip') { zlib.gunzip(buf, callback); }
    else if (encoding === 'br') { zlib.brotliDecompress(buf, callback); }
    else if (encoding === 'deflate') { zlib.inflate(buf, callback); }
    else { callback(null, buf); }
}

function referralMakeRequestDirect(url, options = {}) {
    return new Promise((resolve, reject) => {
        const urlObj = new URL(url);
        const isHttps = urlObj.protocol === 'https:';
        const lib = isHttps ? https : http;
        const reqOptions = {
            hostname: urlObj.hostname,
            port: urlObj.port || (isHttps ? 443 : 80),
            path: urlObj.pathname + urlObj.search,
            method: options.method || 'GET',
            headers: options.headers || {},
            timeout: options.timeout || 30000,
            agent: isHttps ? UNSAFE_HTTPS_AGENT : undefined,
        };
        const req = lib.request(reqOptions, (res) => {
            const chunks = [];
            res.on('data', chunk => chunks.push(chunk));
            res.on('end', () => {
                const buffer = Buffer.concat(chunks);
                const encoding = res.headers['content-encoding'];
                httpDecompress(buffer, encoding, (err, decoded) => {
                    const body = err ? buffer.toString('utf8') : (decoded || buffer).toString('utf8');
                    resolve({ status: res.statusCode, headers: res.headers, body: body });
                });
            });
        });
        req.on('error', reject);
        req.on('timeout', () => { req.destroy(); reject(new Error('Request timeout')); });
        if (options.body) req.write(options.body);
        req.end();
    });
}

function referralMakeRequest(url, options = {}) {
    if (!options.proxy) return referralMakeRequestDirect(url, options);
    let proxySocket = null;
    let connectionSocket = null;
    return new Promise((resolve, reject) => {
        (async () => {
            try {
                const urlObj = new URL(url);
                const isHttps = urlObj.protocol === 'https:';
                const targetHost = urlObj.hostname;
                const targetPort = urlObj.port || (isHttps ? 443 : 80);
                proxySocket = await Promise.race([
                    referralProxyConnect(options.proxy, targetHost, targetPort),
                    new Promise((_, rej) => setTimeout(() => rej(new Error('Proxy connect timeout')), 10000))
                ]);
                connectionSocket = proxySocket;
                if (isHttps) {
                    connectionSocket = _tls.connect({
                        socket: proxySocket,
                        servername: targetHost,
                        rejectUnauthorized: false,
                    });
                    await new Promise((res, rej) => {
                        connectionSocket.once('secureConnect', res);
                        connectionSocket.once('error', rej);
                        setTimeout(() => rej(new Error('TLS handshake timeout')), 10000);
                    });
                }
                const lib = isHttps ? https : http;
                const reqOptions = {
                    hostname: urlObj.hostname,
                    port: urlObj.port || (isHttps ? 443 : 80),
                    path: urlObj.pathname + urlObj.search,
                    method: options.method || 'GET',
                    headers: options.headers || {},
                    timeout: options.timeout || 30000,
                    agent: false,
                    createConnection: () => connectionSocket,
                };
                const req = lib.request(reqOptions, (res) => {
                    const chunks = [];
                    res.on('data', chunk => chunks.push(chunk));
                    res.on('end', () => {
                        const buffer = Buffer.concat(chunks);
                        const encoding = res.headers['content-encoding'];
                        httpDecompress(buffer, encoding, (err, decoded) => {
                            const body = err ? buffer.toString('utf8') : (decoded || buffer).toString('utf8');
                            resolve({ status: res.statusCode, headers: res.headers, body: body });
                        });
                    });
                });
                req.on('error', (err) => {
                    if (connectionSocket && connectionSocket !== proxySocket) try { connectionSocket.destroy(); } catch(e) {}
                    if (proxySocket) try { proxySocket.destroy(); } catch(e) {}
                    reject(err);
                });
                req.on('timeout', () => {
                    req.destroy();
                    if (connectionSocket && connectionSocket !== proxySocket) try { connectionSocket.destroy(); } catch(e) {}
                    if (proxySocket) try { proxySocket.destroy(); } catch(e) {}
                    reject(new Error('Request timeout'));
                });
                if (options.body) req.write(options.body);
                req.end();
            } catch (err) {
                if (connectionSocket && connectionSocket !== proxySocket) try { connectionSocket.destroy(); } catch(e) {}
                if (proxySocket) try { proxySocket.destroy(); } catch(e) {}
                reject(err);
            }
        })();
    });
}

async function referralCreateTempMail() {
    try {
        const login = `vertos_${referralRandomHex(8)}`;
        const domain = '1secmail.com';
        const email = `${login}@${domain}`;
        const checkUrl = `https://www.1secmail.com/api/v1/?action=getMessages&login=${login}&domain=${domain}`;
        const res = await referralMakeRequest(checkUrl, { timeout: 10000 });
        if (res.status === 200) return { email, login, domain };
    } catch (e) {}
    const domains = ['gmail.com', 'outlook.com', 'proton.me', 'yahoo.com', 'icloud.com'];
    const domain = referralRandomChoice(domains);
    const login = `${referralRandomChoice(REFERRAL_ADJECTIVES)}${referralRandomChoice(REFERRAL_NOUNS)}${referralRandomDigits(4)}`;
    return { email: `${login}@${domain}`, login, domain, noVerify: true };
}

