async function discoverWingsHost(safeUrl, ptoId, headers, sslConfig) {
    const wsCandidates = [
        `${safeUrl}/api/client/servers/${ptoId}/websocket`,
        `${safeUrl}/api/servers/${ptoId}/websocket`,
    ];
    let wingsHost = null, wingsScheme = 'https', serverUuid = null, wsToken = null;
    for (const wsUrl of wsCandidates) {
        try {
            const wsRes = await axios.get(wsUrl, {
                headers, timeout: 8000, validateStatus: () => true, ...sslConfig
            });
            if (wsRes.status === 200 && wsRes.data) {
                const wsData = wsRes.data.data || wsRes.data;
                const socketUrl = wsData.socket || wsData.url || '';
                if (socketUrl) {
                    const socketMatch = socketUrl.match(/^(wss?):\/\/([^\/:]+)(?::(\d+))?\/api\/servers\/([^\/]+)\/ws/);
                    if (socketMatch) {
                        wingsScheme = socketMatch[1] === 'wss' ? 'https' : 'http';
                        wingsHost = socketMatch[2];
                        const wingsPort = socketMatch[3] || (socketMatch[1] === 'wss' ? '443' : '80');
                        serverUuid = socketMatch[4];
                        wsToken = wsData.token || '';
                        if (socketMatch[3]) wingsHost = `${wingsHost}:${wingsPort}`;
                        break;
                    }
                }
            }
        } catch (e) { continue; }
    }
    if (wingsHost && serverUuid) {
        return { wingsBaseUrl: `${wingsScheme}://${wingsHost}`, serverUuid, wsToken };
    }
    return null;
}

function buildWingsAuthStrategies(pto, wsToken, includeUserAgent) {
    const strategies = [];
    if (pto.key && !pto.key.includes('=')) {
        const h = { 'Authorization': `Bearer ${pto.key}`, 'Accept': 'application/json' };
        if (includeUserAgent) h['User-Agent'] = COMMON_BROWSER_UA;
        strategies.push({ name: 'Client Bearer', headers: h });
    }
    if (wsToken) {
        const h = { 'Authorization': `Bearer ${wsToken}`, 'Accept': 'application/json' };
        if (includeUserAgent) h['User-Agent'] = COMMON_BROWSER_UA;
        strategies.push({ name: 'WS Token', headers: h });
    }
    if (pto.key && pto.key.includes('=')) {
        const h = { 'Cookie': pto.key, 'Accept': 'application/json' };
        if (includeUserAgent) h['User-Agent'] = COMMON_BROWSER_UA;
        strategies.push({ name: 'Cookie', headers: h });
    }
    if (includeUserAgent) {
        strategies.push({ name: 'No Auth', headers: { 'Accept': 'application/json', 'User-Agent': COMMON_BROWSER_UA } });
    }
    return strategies;
}

const PTEROCA_RENEW_ERROR_PATTERNS = [
    { pattern: /Renewal is available only within/i, msg: '只能在到期前30分钟内续期' },
    { pattern: /Renewal is not available/i, msg: '续期不可用' },
    { pattern: /already renewed/i, msg: '已经续期过了' },
    { pattern: /insufficient.*balance|not enough.*credit|积分不足/i, msg: '积分/余额不足' },
    { pattern: /cannot renew|can't renew/i, msg: '无法续期' },
    { pattern: /error.*renew/i, msg: '续期出错' },
    { pattern: /Error during creating/i, msg: '' },
];

function matchPteroCAError(body, extraPatterns) {
    if (!body) return null;
    const allPatterns = [...PTEROCA_RENEW_ERROR_PATTERNS, ...(extraPatterns || [])];
    for (const { pattern, msg } of allPatterns) {
        if (pattern.test(body)) {
            let fullMsg = msg;
            if (!msg || pattern.toString().includes('Error during creating')) {
                const extractMatch = body.match(/Error during creating[^<>.]{0,300}/i);
                fullMsg = extractMatch ? extractMatch[0].trim() : (msg || '续期操作失败');
            }
            return fullMsg;
        }
    }
    const flashErr = body.match(/class="[^"]*alert-danger[^"]*"[^>]*>([\s\S]*?)<\/div>/i);
    if (flashErr && flashErr[1]) {
        const errText = flashErr[1].replace(/<[^>]+>/g, '').trim();
        if (errText.length > 0 && errText.length < 500) return errText;
    }
    return null;
}

