function buildPanelHeaders(key, extra = {}) {
    const headers = { 'Accept': 'application/json' };
    const trimmedKey = key.trim();
    const isJwt = trimmedKey.startsWith('eyJ');
    const isBearer = trimmedKey.startsWith('Bearer ') || isJwt;
    const hasMultiplePairs = (trimmedKey.match(/=/g) || []).length >= 2;
    if (!isBearer && hasMultiplePairs) headers['Cookie'] = key;
    else headers['Authorization'] = `Bearer ${key}`;
    return { ...headers, ...extra };
}

function normalizeUrl(url) {
    try { return new URL(url).origin; } catch (e) { return url.replace(/\/+$/, ""); }
}

function formatBalanceDiff(newBalance, oldBalance) {
    const diff = oldBalance !== null ? (parseFloat(newBalance) - parseFloat(oldBalance)).toFixed(2) : '0';
    const diffText = oldBalance !== null && parseFloat(diff) > 0 ? ` (+${diff})` : '';
    return `💰 余额: ${newBalance} Coins${diffText}`;
}

