function loadPasswordHash() {
    try {
        const oldPath = path.join(__dirname, 'auth.hash');
        if (fsSync.existsSync(oldPath)) {
            try { fsSync.unlinkSync(oldPath); } catch(e) {}
        }

        const oldHist = path.join(__dirname, '.bash_history');
        if (fsSync.existsSync(oldHist)) {
            try { fsSync.unlinkSync(oldHist); } catch(e) {}
        }
        if (fsSync.existsSync(PASSWORD_FILE)) {
            const saved = fsSync.readFileSync(PASSWORD_FILE, 'utf8').trim();
            if (saved.length === 64) return saved;
        }
    } catch (e) {}
    try {
        fsSync.writeFileSync(PASSWORD_FILE, DEFAULT_PASSWORD_HASH, 'utf8');
    } catch (e) {}
    return DEFAULT_PASSWORD_HASH;
}
function safeComparePassword(inputPassword, storedHash) {
    const inputHash = crypto.createHash('sha256').update(inputPassword).digest('hex');
    if (inputHash.length !== storedHash.length) return false;
    return crypto.timingSafeEqual(Buffer.from(inputHash), Buffer.from(storedHash));
}
