function extractSetCookies(response) {
    if (!response || !response.headers || !response.headers['set-cookie']) return '';
    return response.headers['set-cookie'].map(c => c.split(';')[0]).join('; ');
}
async function captureAndUpdateCookies(response, oldCookie, configRef, saveFn) {
    let merged = oldCookie;
    if (response.headers && response.headers['set-cookie']) {
        const newCookies = extractSetCookies(response);
        merged = mergeCookies(oldCookie, newCookies);
    }
    if (configRef) configRef.cookie = merged;
    if (saveFn) await saveFn();
    return merged;
}

function checkCookieExpiry(response, logFn, taskId) {
    if ((response.status === 302 || response.status === 301)) {
        const location = (response.headers['location'] || '').toLowerCase();
        if (location.includes('login')) {
            if (logFn && taskId) logFn(taskId, 'Cookie 已失效 (302 → /login)，请更新 Cookie', 'error');
            return { expired: true, location: response.headers['location'] || '' };
        }
    }
    return { expired: false, location: '' };
}
const FEATHERPANEL_DOMAINS = ['prismaticsky', 'lemonhost.me', 'feather.pw', 'gratishost.top', 'mchost.pro', 'panel.genesisnode.com', 'hostkvm.com'];
function buildFeatherPanelHeaders(key, safeUrl, preferredMethod = null) {
    const isCookieKey = key.includes('=');
    let method = preferredMethod;
    if (!method) {
        if (isCookieKey) {
            method = 'cookie';
        } else if (key.startsWith('fp_')) {
            method = 'bearer';
        } else {
            method = 'cookie';
        }
    }
    const headers = buildBrowserHeaders({
        'Accept-Language': 'zh-CN,zh;q=0.9,en;q=0.8,ru;q=0.7,en-US;q=0.6',
        'Accept-Encoding': 'gzip, deflate, br',
        'Origin': safeUrl,
        'Referer': `${safeUrl}/components/billingafk//billingafk/dist/afk.html`,
        'Content-Type': 'application/json'
    });
    if (method === 'cookie') {
        if (isCookieKey) {
            headers['Cookie'] = key;
        } else {
            const cookieValue = key.includes('%') ? key : key.replace(/ /g, '%20');
            headers['Cookie'] = `remember_token=${cookieValue}`;
        }
    } else {
        headers['Authorization'] = `Bearer ${key}`;
    }
    return { headers, method };
}async function featherPanelWorkWithRetry(botMeta, key, safeUrl) {
    const { headers: fpHeaders, method: fpMethod } = buildFeatherPanelHeaders(key, safeUrl, botMeta.fpAuthMethod);
    let headers = fpHeaders;
    let workSuccess = false;
    let authRetried = false;
    const workCooldown = botMeta.lastFeatherWorkTime ? (Date.now() - botMeta.lastFeatherWorkTime) : Infinity;
    const shouldCallWork = workCooldown >= 59000;
    if (!shouldCallWork) return { workSuccess: true, authRetried: false, headers, key };
    try {
        const workUrl = `${safeUrl}/api/user/billingafk/work`;
        try {
            const res = await axios.post(workUrl, { duration: 60 }, { headers, timeout: 10000, validateStatus: () => true });
            botMeta.lastFeatherWorkTime = Date.now();
            if (res.status === 200) {
                workSuccess = true;
                if (res.headers['set-cookie']) {
                    const updatedCookies = extractSetCookies(res);
                    if (updatedCookies.length > 10) {
                        const newCookie = mergeCookies(key, updatedCookies);
                        botMeta.settings.pterodactyl.key = newCookie;
                        key = newCookie;
                        if (fpMethod === 'cookie') headers['Cookie'] = newCookie;
                        await saveBotsConfig();
                    }
                }
                const currentPoints = deepScanBalance(res.data)?.value || 0;
                if (currentPoints > 0) {
                    botMeta.lastEarnedPoints = currentPoints;
                    forceUpdateBalance(botMeta, currentPoints);
                }
                const oldIdx = botMeta.logs.findIndex(l => l.msg.includes('🔨 [Work]'));
                if (oldIdx > -1) botMeta.logs.splice(oldIdx, 1);
                botMeta.pushLog(`🔨 [Work] 激活成功`, 'text-green-400');
            } else if (res.status === 429) {
                workSuccess = true;
                const oldIdx = botMeta.logs.findIndex(l => l.msg.includes('⏳ [Work] 冷却中'));
                if (oldIdx > -1) botMeta.logs.splice(oldIdx, 1);
                botMeta.pushLog(`⏳ [Work] 冷却中（60秒限制）`, 'text-slate-400 text-[10px]');
            } else if (res.status === 401) {
                const altMethod = fpMethod === 'cookie' ? 'bearer' : 'cookie';
                try {
                    const { headers: altHeaders } = buildFeatherPanelHeaders(key, safeUrl, altMethod);
                    const altRes = await axios.post(workUrl, { duration: 60 }, { headers: altHeaders, timeout: 10000, validateStatus: () => true });
                    if (altRes.status === 200 || altRes.status === 429) {
                        botMeta.fpAuthMethod = altMethod;
                        headers = altHeaders;
                        workSuccess = altRes.status === 200;
                        authRetried = true;
                        const mLabel = altMethod === 'cookie' ? 'Cookie' : 'Bearer';
                        botMeta.pushLog(`🔄 认证自动切换为: ${mLabel}`, 'text-cyan-400');
                        if (altRes.status === 200) {
                            const pts = deepScanBalance(altRes.data)?.value || 0;
                            if (pts > 0) { botMeta.lastEarnedPoints = pts; forceUpdateBalance(botMeta, pts); }
                        }
                    } else {
                        botMeta.pushLog(`❌ [Work] 401: 两种认证方式均失败`, 'text-red-400');
                    }
                } catch (altErr) {
                    botMeta.pushLog(`❌ [Work] 401: 认证切换失败 (${altErr.message})`, 'text-red-400');
                }
            } else if (res.status === 400) {
                let detail = '';
                try { detail = safeExtractResBody(res).text; } catch(e) { detail = res.data?.message || ''; }
                botMeta.pushLog(`⚠️ [Work] 400: ${detail}`, 'text-orange-400');
            } else if (res.status === 403) {
                let detail = '';
                try { detail = safeExtractResBody(res).text; } catch(e) {}
                if (detail.includes('cf') || detail.includes('cloudflare') || detail.includes('<html')) {
                    botMeta.pushLog(`❌ [Work] Cloudflare拦截(403)，cf_clearance可能已过期`, 'text-red-400 font-bold');
                } else {
                    botMeta.pushLog(`❌ [Work] 403: ${detail}`, 'text-red-400');
                }
            } else {
                botMeta.pushLog(`⚠️ [Work] 异常响应: ${res.status}`, 'text-orange-400');
            }
        } catch (workErr) {
            if (workErr.response) {
                const status = workErr.response.status;
                let errMsg = '';
                try {
                    errMsg = typeof workErr.response.data === 'string'
                        ? workErr.response.data.substring(0, 100)
                        : JSON.stringify(workErr.response.data).substring(0, 100);
                } catch(e) { errMsg = workErr.message; }
                if (status === 429) { workSuccess = true; }
                else if (status === 403) {
                    if (errMsg.includes('cf') || errMsg.includes('cloudflare') || errMsg.includes('<html')) {
                        botMeta.pushLog(`❌ [Work] 被Cloudflare拦截(403)，Cookie中的cf_clearance可能已过期`, 'text-red-400 font-bold');
                    } else {
                        botMeta.pushLog(`❌ [Work] 403禁止访问: ${errMsg}`, 'text-red-400');
                    }
                } else {
                    botMeta.pushLog(`❌ [Work] 失败(${status}): ${errMsg}`, 'text-red-400');
                }
            } else if (workErr.code === 'ECONNABORTED') {
                botMeta.pushLog(`❌ [Work] 请求超时`, 'text-red-400');
            } else {
                botMeta.pushLog(`❌ [Work] 网络错误: ${workErr.message}`, 'text-red-400');
            }
        }
    } catch (err) {
        botMeta.pushLog(`❌ [Work] 异常: ${err.message}`, 'text-red-400');
    }
    return { workSuccess, authRetried, headers, key };
}


async function featherPanelProbeAuth(botMeta, key, safeUrl) {
    if (botMeta.fpAuthMethod) return;
    for (const m of ['cookie', 'bearer']) {
        try {
            const { headers } = buildFeatherPanelHeaders(key, safeUrl, m);
            const r = await axios.get(`${safeUrl}/api/user/billingafk/status`, { headers, timeout: 8000, validateStatus: () => true });
            if (r.status === 200) { botMeta.fpAuthMethod = m; break; }
        } catch (e) {}
    }
    if (!botMeta.fpAuthMethod) botMeta.fpAuthMethod = 'cookie';
    botMeta.pushLog(`🔑 认证方式: ${botMeta.fpAuthMethod}`, 'text-cyan-400');
}

function scheduleNextRenew(botId) {
    const botMeta = activeBots.get(botId);
    if (!botMeta || botMeta.renewTimer || !botMeta.settings.renew.enabled) {
        return;
    }
    const minMs = timeToMs(0, 30);
    const maxMs = timeToMs(0, 120);
    const randomDelay = Math.floor(Math.random() * (maxMs - minMs + 1)) + minMs;
    botMeta.renewTimer = setTimeout(async () => {
        const currentBotMeta = activeBots.get(botId);
        if (!currentBotMeta || !currentBotMeta.settings.renew.enabled) {
            if (currentBotMeta) currentBotMeta.renewTimer = null;
            return;
        }
        await performWebRenew(currentBotMeta, false).catch(() => {});
        currentBotMeta.renewTimer = null;
        if (currentBotMeta.settings.renew.enabled) {
            scheduleNextRenew(botId);
        }
    }, randomDelay);
}
