                        if (mergedCookie !== rawCookie && task.config) {
                            task.config.cookie = mergedCookie;
                            try { await saveTaskCenterConfig(); } catch(e) {}
                            _renewLog(task, `🔄 续期后已更新 Cookie (XSRF-TOKEN / session)`, 'success');
                        }
