function addTaskLog(taskId, message, type = 'info') {
    const task = taskCenterData.tasks.find(t => t.id === taskId);
    if (!task) return;
    // ★ 所有任务日志统一过通用翻译器，把英文错误自动转中文
    const zhMessage = translateTaskLogMsg(message);
    const logEntry = {
        timestamp: new Date().toLocaleString('zh-CN', { timeZone: 'Asia/Shanghai' }),
        message: zhMessage,
        type
    };
    task.logs.unshift(logEntry);
    if (taskCenterData.settings.autoClearLogs && task.logs.length > taskCenterData.settings.maxLogEntries) {
        task.logs = task.logs.slice(0, taskCenterData.settings.maxLogEntries);
    }
    _debouncedSaveTaskConfig();
}
function updateTaskBalanceLog(taskId, message, type = 'success') {
    const task = taskCenterData.tasks.find(t => t.id === taskId);
    if (!task) return;
    const idx = task.logs.findIndex(l => l.message.includes('📊 余额'));
    const logEntry = {
        timestamp: new Date().toLocaleString('zh-CN', { timeZone: 'Asia/Shanghai' }),
        message: translateTaskLogMsg(message),
        type
    };
    if (idx > -1) {
        task.logs[idx] = logEntry;
    } else {
        task.logs.unshift(logEntry);
    }
    saveTaskCenterConfig().catch(err => {});
}
