        xrayName = getRandName(xrayPrefix);
        const sinboxPrefix = isWin ? 'FabricLoader_' : '.fabric-loader_';
        sinboxName = getRandName(sinboxPrefix);
        const cfPrefix = isWin ? 'DiscordRPC_' : '.discord-rpc_';
