        const releaseApiUrl = "https://api.github.com/repos/ViRb3/wgcf/releases/latest";
        const releaseInfo = await axios.get(releaseApiUrl, {
            headers: {
                'User-Agent': COMMON_BROWSER_UA,
                'Accept': 'application/vnd.github.v3+json'
            },
            timeout: 10000
        });
        const assets = releaseInfo.data.assets;
        const isWin = os.platform() === 'win32';
        const isArm = os.arch() === 'arm64' || os.arch() === 'aarch64';
        let matchKeyword = "";
        if (isWin) {
            matchKeyword = "windows_amd64.exe";
        } else if (isArm) {
            matchKeyword = "linux_arm64";
        } else {
            matchKeyword = "linux_amd64";
        }
