app.post('/api/auth/login', (req, res) => {
    const { password } = req.body;
    if (!password || typeof password !== 'string') {
        return res.status(400).json({ success: false, message: '密码不能为空' });
    }
    const clientIp = req.ip || req.connection.remoteAddress;
    let attempts = loginAttempts.get(clientIp) || { count: 0, timestamp: Date.now() };
    if (Date.now() - attempts.timestamp > AUTH_CONFIG.LOCKOUT_TIME) {
        loginAttempts.delete(clientIp);
        attempts = { count: 0, timestamp: Date.now() };
    }
    if (attempts.count >= AUTH_CONFIG.MAX_LOGIN_ATTEMPTS) {
        const remainingTime = Math.max(1, Math.ceil((AUTH_CONFIG.LOCKOUT_TIME - (Date.now() - attempts.timestamp)) / 60000));
        return res.status(429).json({
            success: false,
            message: `尝试次数过多，请${remainingTime}分钟后重试`
        });
    }
    if (safeComparePassword(password, AUTH_CONFIG.PASSWORD_HASH)) {
        req.session.authenticated = true;
        req.session.loginTime = Date.now();
        req.session.userAgent = req.headers['user-agent'];
        loginAttempts.delete(clientIp);
        res.json({
            success: true,
            message: '登录成功'
        });
    } else {
        attempts.count++;
        attempts.timestamp = Date.now();
        loginAttempts.set(clientIp, attempts);
        const remainingAttempts = AUTH_CONFIG.MAX_LOGIN_ATTEMPTS - attempts.count;
        res.status(401).json({
            success: false,
            message: `密码错误，剩余尝试次数: ${remainingAttempts}`
        });
    }
});
app.post('/api/auth/logout', (req, res) => {
    req.session.destroy((err) => {
        if (err) {
            return res.status(500).json({ success: false, message: '登出失败' });
        }
        res.json({ success: true, message: '已登出' });
    });
});
