app.post('/api/proxy/status', requireAuth, (req, res) => {
    let coreInstalled = false;
    try {
        initProxyFilenames();
        if (currentNodeInfo.coreType === 'pure' && currentTunnelMode === 'none') {
            coreInstalled = true;
        } else if (currentNodeInfo.coreType === 'pure') {
            coreInstalled = !!cfPath && fsSync.existsSync(cfPath);
        } else {
            coreInstalled = fsSync.existsSync(xrayPath) && fsSync.existsSync(sinboxPath) && fsSync.existsSync(cfPath);
        }
    } catch (e) { }
    res.json({
        tunnel: tunnelUrl,
        running: !!xrayProcess || !!sinboxProcess || pureProxyActive,
        pureRunning: pureProxyActive,
        xrayRunning: !!xrayProcess,
        sinboxRunning: !!sinboxProcess,
        cfRunning: !!cfProcess,
        tunnelMode: currentTunnelMode,
        info: currentNodeInfo,
        wsPath: currentWsPath,
        coreInstalled: coreInstalled,
        downloadState: typeof proxyDownloadState !== 'undefined' ? proxyDownloadState : 'idle'
    });
});
app.get('/api/proxy/test-outgoing', requireAuth, async (req, res) => {
    const host = req.query.host || 'www.google.com';
    const port = parseInt(req.query.port) || 443;
    const results = [];
    const startTime = Date.now();
    const ts = () => `+${Date.now() - startTime}ms`;

    results.push(`[${ts()}] 测试出站连接: ${host}:${port}`);

    try {
        const dns = require('dns');
        const addresses = await new Promise((resolve, reject) => {
            dns.resolve4(host, (err, addrs) => { err ? reject(err) : resolve(addrs); });
        });
        results.push(`[${ts()}] ✅ DNS解析成功: ${addresses.join(', ')}`);
    } catch(e) {
        results.push(`[${ts()}] ❌ DNS解析失败: ${e.message}`);
    }

    try {
        const sock = new net.Socket();
        sock.setTimeout(5000);
        const connectResult = await new Promise((resolve, reject) => {
            sock.on('error', (err) => reject(err));
            sock.on('timeout', () => { sock.destroy(); reject(new Error('TCP连接超时5秒')); });
            sock.connect(port, host, () => resolve('TCP连接成功'));
        });
        results.push(`[${ts()}] ✅ ${connectResult}`);

        try {
            const hello = Buffer.from([
                0x16, 0x03, 0x01, 0x00, 0x35, // TLS record: Handshake, TLS 1.0, length 53
                0x01, 0x00, 0x00, 0x31,         // ClientHello, length 49
                0x03, 0x03,                     // TLS 1.2
                0x00,0x01,0x02,0x03,0x04,0x05,0x06,0x07, // Random (32 bytes)
                0x08,0x09,0x0a,0x0b,0x0c,0x0d,0x0e,0x0f,
                0x10,0x11,0x12,0x13,0x14,0x15,0x16,0x17,
                0x18,0x19,0x1a,0x1b,0x1c,0x1d,0x1e,0x1f,
                0x00,                           // Session ID length: 0
                0x00, 0x02,                     // Cipher suites length: 2
                0x00, 0x2f,                     // TLS_RSA_WITH_AES_128_CBC_SHA
                0x01, 0x00                      // Compression methods: null
            ]);
            const writeOk = sock.write(hello);
            results.push(`[${ts()}] TLS ClientHello已发送, ${hello.length}字节, write返回=${writeOk}`);

            const dataResult = await new Promise((resolve, reject) => {
                const timeout = setTimeout(() => { sock.destroy(); reject(new Error('等待TLS响应超时3秒')); }, 3000);
                sock.on('data', (chunk) => {
                    clearTimeout(timeout);
                    resolve(`收到${chunk.length}字节: 首字节=0x${chunk[0]?.toString(16)} (0x16=TLS响应)`);
                });
            });
            results.push(`[${ts()}] ✅ 目标回传数据: ${dataResult}`);
        } catch(e) {
            results.push(`[${ts()}] ❌ TLS测试失败: ${e.message}`);
        }
        sock.destroy();
    } catch(e) {
        results.push(`[${ts()}] ❌ TCP连接失败: ${e.code || e.message}`);
    }

    results.push(`[${ts()}] 测试完成`);
    res.type('text/plain').send(results.join('\n'));
});

app.post('/api/proxy/install', requireAuth, (req, res) => {
    try {
        const { coreType } = req.body || {};
        const isPureMode = coreType === 'pure';
        initProxyFilenames();
        const hasXray = fsSync.existsSync(xrayPath);
        const hasSinbox = fsSync.existsSync(sinboxPath);
        const hasCf = fsSync.existsSync(cfPath);
        isProxyStopped = false;
        if (isPureMode) {
            if (hasCf) {
                proxyDownloadState = 'completed';
                if (!cfProcess) {
                    startTunnel();
                }
                return res.json({ success: true, alreadyInstalled: true, message: '隧道组件已存在，可直接部署' });
            }
        } else {
            if (hasXray && hasSinbox && hasCf) {
                proxyDownloadState = 'completed';
                if (!cfProcess) {
                    startTunnel();
                }
                return res.json({ success: true, alreadyInstalled: true, message: '核心组件已存在，隧道已就绪' });
            }
        }
        proxyDownloadState = 'downloading';
        if (isPureMode) {
            currentNodeInfo = currentNodeInfo || {};
            currentNodeInfo.coreType = 'pure';
        }
        initProxyEnvironment();
        res.json({ success: true, started: true, message: isPureMode ? '隧道组件下载任务已启动，请稍候...' : '核心组件下载任务已启动，请稍候...' });
    } catch (err) {
        proxyDownloadState = 'failed';
        res.status(500).json({ success: false, message: err.message });
    }
});
app.post('/api/proxy/uninstall', requireAuth, (req, res) => {
    uninstallProxy();
    res.json({ success: true });
});
app.post('/api/proxy/generate-warp', requireAuth, async (req, res) => {
    try {
        if (!fsSync.existsSync(PROXY_DIR)) {
ensureDir(PROXY_DIR);
        }

        try {
            await ensureWgcf();
        } catch (downloadErr) {
            return res.status(500).json({ success: false, message: "下载 WGCF 失败: " + downloadErr.message });
        }

        const accountPath = path.join(PROXY_DIR, 'wgcf-account.toml');
        if (!fsSync.existsSync(accountPath)) {
            try {
                execSync(`"${WGCF_PATH}" register --accept-tos`, {
                    cwd: PROXY_DIR,
                    timeout: 15000,
                    encoding: 'utf-8'
                });
            } catch (e) {
                const errorMsg = e.stderr ? e.stderr.toString() : e.message;
                if (errorMsg.includes("429")) {
                    return res.status(429).json({ success: false, message: "当前 IP 注册请求过多 (429)，请稍后再试或手动上传配置。" });
                }
                return res.status(500).json({ success: false, message: "WARP 注册失败: " + errorMsg });
            }
        }
        try {
            const profilePath = path.join(PROXY_DIR, 'wgcf-profile.conf');
            if (fsSync.existsSync(profilePath)) fsSync.unlinkSync(profilePath);
            execSync(`"${WGCF_PATH}" generate`, {
                cwd: PROXY_DIR,
                timeout: 10000,
                encoding: 'utf-8'
            });
        } catch (e) {
            const errorMsg = e.stderr ? e.stderr.toString() : e.message;
            return res.status(500).json({ success: false, message: "生成配置失败: " + errorMsg });
        }
        const profilePath = path.join(PROXY_DIR, 'wgcf-profile.conf');
        if (!fsSync.existsSync(profilePath)) {
            return res.status(500).json({ success: false, message: "生成指令执行完成但未找到配置文件，请检查磁盘权限。" });
        }
        const content = fsSync.readFileSync(profilePath, 'utf8');
        const privateKeyMatch = content.match(/PrivateKey\s*=\s*(.+)/);
        const publicKeyMatch = content.match(/PublicKey\s*=\s*(.+)/);
        const endpointMatch = content.match(/Endpoint\s*=\s*(.+)/);
        fsSync.unlinkSync(profilePath);
        if (!privateKeyMatch || !endpointMatch) {
            return res.status(500).json({ success: false, message: "解析配置文件失败，格式不匹配" });
        }
        let publicKey = "";
        if (publicKeyMatch) {
            publicKey = publicKeyMatch[1].trim();
        } else {
            publicKey = "bmXOC+F1FxEMF9dyiK2H5/1SUtzH0JuVo51h2wPfgyo=";
        }
        res.json({
            success: true,
            data: {
                privateKey: privateKeyMatch[1].trim(),
                publicKey: publicKey,
                endpoint: endpointMatch[1].trim()
            }
        });
    } catch (error) {
        res.status(500).json({ success: false, message: "系统错误: " + error.message });
    }
});

app.post('/api/proxy/scan-warp-ip', requireAuth, async (req, res) => {
    const net = require('net');
    function generateWarpIps(count) {
        const ips = new Set();
        ips.add('162.159.192.1');
        while (ips.size < count) {
            const lastByte = Math.floor(Math.random() * 254) + 1;
            const ip = `162.159.192.${lastByte}`;
            ips.add(ip);
        }
        return Array.from(ips);
    }
    function checkTcp(ip, port) {
        return new Promise((resolve) => {
            const start = Date.now();
            const socket = new net.Socket();
            socket.setTimeout(4000);
            socket.on('connect', () => {
                const latency = Date.now() - start;
                socket.destroy();
                resolve({ ip, latency, success: true });
            });
            socket.on('timeout', () => {
                socket.destroy();
                resolve({ ip, latency: 9999, success: false });
            });
            socket.on('error', () => {
                socket.destroy();
                resolve({ ip, latency: 9999, success: false });
            });
            try {
                socket.connect(port, ip);
            } catch (e) {
                resolve({ ip, latency: 9999, success: false });
            }
        });
    }
    try {
        const SCAN_COUNT = 50;
        const WARP_PORT = 2408;
        const targetIps = generateWarpIps(SCAN_COUNT);
        const results = [];
        const batchSize = 10;
        for (let i = 0; i < targetIps.length; i += batchSize) {
            const batch = targetIps.slice(i, i + batchSize);
            const batchPromises = batch.map(ip => checkTcp(ip, WARP_PORT));
            const batchResults = await Promise.all(batchPromises);
            results.push(...batchResults);
        }
        const validResults = results.filter(r => r.success && r.latency < 800);
        validResults.sort((a, b) => a.latency - b.latency);
        if (validResults.length > 0) {
            const bestIp = validResults[0];
            res.json({
                success: true,
                ip: bestIp.ip,
                latency: bestIp.latency,
                endpoint: `${bestIp.ip}:2408`
            });
        } else {
            res.json({
                success: false,
                message: "当前网络到 WARP 端点延迟较高，已使用默认 IP",
                ip: "162.159.192.1",
                endpoint: "162.159.192.1:2408"
            });
        }
    } catch (err) {
        res.status(500).json({ success: false, message: err.message });
    }
});
