    '<div id="rcon-download-modal" class="fixed inset-0 bg-black/80 flex items-center justify-center z-[60] hidden" role="dialog" aria-modal="true" aria-label="远程下载插件">',
    '    <div class="bg-slate-900 rounded-2xl p-6 w-full max-w-lg border border-purple-500/30 shadow-2xl">',
    '        <div class="flex justify-between items-center mb-4">',
    '            <h3 class="text-lg font-bold text-white"><i class="fas fa-download text-purple-400 mr-2"></i>远程下载插件</h3>',
    '            <button onclick="closeRconDownload()" class="text-slate-400 hover:text-white">&times;</button>',
    '        </div>',
    '        <div id="rcon-bot-status" class="flex items-center gap-2 mb-3 text-[11px]">',
    '            <span class="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>',
    '            <span class="text-emerald-400">Bot 在线，将通过游戏命令下载</span>',
    '        </div>',
    '        <div class="mb-4">',
    '            <label class="block text-xs text-slate-400 mb-1.5">插件下载链接 <span class="text-purple-400">(.jar 直链)</span></label>',
    '            <div class="flex gap-2">',
