    '                <button onclick="executeRconDownload()" id="rcon-download-btn" class="bg-purple-600 hover:bg-purple-500 text-white px-5 py-2.5 rounded-lg text-sm font-bold transition-colors flex items-center gap-2 shrink-0">',
    '                    <i class="fas fa-cloud-download-alt"></i> 下载',
