    '                            <label class="block text-sm text-slate-400 mb-1">注册地址 *</label>',
    '                            <input id="new-referral-url" type="url" class="w-full px-3 py-2 bg-slate-800 border border-slate-700 rounded-lg text-sm" ',
    '                                   placeholder="https://dash.vertos.in 或 https://vektalnodes.in/register?ref=xxx" required value="${task?.config?.referralUrl || \'\'}">',
    '                            <p class="text-xs text-slate-500 mt-1">支持 Vertos、VektalNodes 等面板，自动检测类型</p>',
    '                        </div>',
