    '                                    <option value="1" ${task?.config?.referralCount === \'1\' ? \'selected\' : \'\'}>1次</option>',
    '                                    <option value="5" ${task?.config?.referralCount === \'5\' ? \'selected\' : \'\'}>5次</option>',
    '                                    <option value="10" ${!task?.config?.referralCount || task?.config?.referralCount === \'10\' ? \'selected\' : \'\'}>10次</option>',
    '                                    <option value="20" ${task?.config?.referralCount === \'20\' ? \'selected\' : \'\'}>20次</option>',
    '                                    <option value="50" ${task?.config?.referralCount === \'50\' ? \'selected\' : \'\'}>50次</option>',
    '                                    <option value="100" ${task?.config?.referralCount === \'100\' ? \'selected\' : \'\'}>100次</option>',
    '                                </select>',
    '                            </div>',
    '                            <div>',
    '                                <label class="block text-sm text-slate-400 mb-1">注册间隔</label>',
    '                                <div class="time-input-grid">',
