    '                                   class="w-full px-3 py-2 bg-slate-800 border border-slate-700 rounded-lg text-sm" ',
    '                                   placeholder="https://example.com/renew"',
    '                                   onchange="updateTaskConfig(\'renewUrl\', this.value)"',
    '                                   oninput="updateRenewHint(this.value)">',
    '                            <p id="renew-hint" class="text-xs text-slate-500 mt-1">支持面板: PteroCA / Zytrano / Icehost / Epichost / Aida / Keitocloud / 通用HTTP</p>',
    '                        </div>',
    '                        <div id="zytrano-info-edit" class="hidden bg-amber-900/30 border border-amber-500/30 rounded-xl p-3 space-y-1">',
    '                            <p class="text-xs font-bold text-amber-400"><i class="fas fa-info-circle"></i> Zytrano 面板自动识别</p>',
    '                            <p class="text-xs text-amber-300">• Cookie 字段填写浏览器 F12→Network 复制的完整 Cookie</p>',
    '                            <p class="text-xs text-amber-300">• 必须包含: cf_clearance + XSRF-TOKEN + xxx_session</p>',
    '                            <p class="text-xs text-amber-300">• 续期方式: PATCH /servers/renew/{id}，自动携带 CSRF Token</p>',
    '                            <p class="text-xs text-amber-300">• 每 14 分钟自动刷新 Cookie，保持 Session 活跃</p>',
    '                            <p class="text-xs text-amber-300">• Session 有效期约 2 小时，过期需重新复制 Cookie</p>',
    '                        </div>',
    '                        <div>',
    '                            <label class="block text-sm text-slate-400 mb-1">请求方法</label>',
    '                            <select class="w-full px-3 py-2 bg-slate-800 border border-slate-700 rounded-lg text-sm" ',
    '                                    onchange="updateTaskConfig(\'method\', this.value)">',
    '                                <option value="POST" ${task.config.method === \'POST\' ? \'selected\' : \'\'}>POST</option>',
    '                                <option value="GET" ${task.config.method === \'GET\' ? \'selected\' : \'\'}>GET</option>',
    '                                <option value="PUT" ${task.config.method === \'PUT\' ? \'selected\' : \'\'}>PUT</option>',
    '                                <option value="PATCH" ${task.config.method === \'PATCH\' ? \'selected\' : \'\'}>PATCH</option>',
    '                            </select>',
    '                        </div>',
    '                        ${commonLoginFields}',
    '                    </div>',
    '                `;',
    '                break;',
    '            case \'afk\':',
    '                html = `',
    '                    <div class="space-y-4">',
