app.post("/api/task-center/:taskId/test-referral", requireAuth, async (req, res) => {
    try {
        const task = taskCenterData.tasks.find(t => t.id === req.params.taskId);
        if (!task) {
            return res.status(404).json({ success: false, message: '任务不存在' });
        }
        if (task.type !== 'referral') {
            return res.json({ success: false, message: '此任务不是自动注册任务' });
        }
        const { referralUrl, referralRefCode } = task.config;
        if (!referralUrl) {
            return res.json({ success: false, message: '未配置注册地址' });
        }
        addTaskLog(task.id, `开始测试注册(1次)...`, 'info');
        let baseUrl = referralUrl;
        let refCode = referralRefCode || '';
        try {
            const urlObj = new URL(referralUrl);
            baseUrl = `${urlObj.protocol}//${urlObj.host}`;
            const refParam = urlObj.searchParams.get('ref');
            if (refParam && !refCode) refCode = refParam;
        } catch(e) {}

        const result = await referralRegisterOne(baseUrl, refCode, null);
        if (result.success) {
            addTaskLog(task.id, `注册测试成功: ${result.account.username} (${result.account.email})`, 'success');
            if (!task.config.referralAccounts) task.config.referralAccounts = [];
            task.config.referralAccounts.push(result.account);
            try { await saveTaskCenterConfig(); } catch(e) {}
            res.json({
                success: true,
                message: `注册成功: ${result.account.username}`,
                username: result.account.username,
                email: result.account.email
            });
        } else {
            addTaskLog(task.id, `注册测试失败: ${result.error}`, 'error');
            res.json({ success: false, message: result.error });
        }
    } catch (err) {
        addTaskLog(req.params.taskId, `注册测试异常: ${err.message}`, 'error');
        res.status(500).json({ success: false, message: err.message });
    }
});
