app.post("/api/bots/:id/toggle-keepalive", requireAuth, async (req, res) => {
    try {
        const b = activeBots.get(req.params.id);
        if (!b) return res.status(404).json({ success: false, message: "机器人不存在" });
        const currentKey = (b.settings.pterodactyl?.key || "").trim().toLowerCase();
        const currentType = b.settings.pterodactyl?.type || "";
        let typeMismatch = false;
        let errorMsg = "";
        if (currentKey.startsWith('ptlc')) {
            if (currentType !== 'pterodactyl') {
                typeMismatch = true;
                errorMsg = `类型不适配：Key 为 Pterodactyl 专用，但面板选择为 ${currentType || '未知'}，无法启动守护`;
            }
        }
        else if (currentKey.startsWith('fp_')) {
            if (currentType !== 'featherpanel') {
                typeMismatch = true;
                errorMsg = `类型不适配：Key 为 FeatherPanel 专用，但面板选择为 ${currentType || '未知'}，无法启动守护`;
            }
        }
        else if (currentKey.includes('=') && currentType === 'pterodactyl') {
            typeMismatch = true;
            errorMsg = `路径不匹配：Key 为 Cookie 格式，通常不用于标准 Pterodactyl 面板，无法启动守护`;
        }
        if (typeMismatch) {
            b.pushLog(`❌ ${errorMsg}`, 'text-red-500 font-bold animate-pulse');
            return res.status(400).json({
                success: false,
                message: errorMsg + "，请修改面板类型或凭据后重试。"
            });
        }
        b.settings.keepAlive = !b.settings.keepAlive;
        if (b.settings.keepAlive) {
            startServerMonitor(b.id);
        } else {
            if (typeof pteroMonitorTimers !== 'undefined' && pteroMonitorTimers.has(b.id)) {
                clearInterval(pteroMonitorTimers.get(b.id));
                pteroMonitorTimers.delete(b.id);
            }
            b.pushLog(`🛡️ 服务器守护进程已关闭`, 'text-slate-400');
        }
        await saveBotsConfig();
        res.json({ success: true, status: b.settings.keepAlive });
    } catch (err) {
        res.status(500).json({ success: false, message: err.message });
    }
});
