function smartParsePterodactylUrl(inputUrl, inputId, inputKey) {
    let result = {
        url: inputUrl,
        id: inputId,
        type: 'pterodactyl',
        path: '',
        autoAfk: false
    };
    let forcedType = null;
    if (inputKey) {
        const keyLower = inputKey.toLowerCase();
        if (keyLower.startsWith('fp_')) {
            forcedType = 'featherpanel';
            result.type = 'featherpanel';
            result.path = '/api/user/billingafk/status';
        }
        else if (keyLower.startsWith('ptlc')) {
            forcedType = 'pterodactyl';
            result.type = 'pterodactyl';
        }
    }
    if (!inputUrl) return result;
    let targetUrl = inputUrl.trim();
    if (!targetUrl.startsWith('http')) {
        targetUrl = 'https://' + targetUrl;
    }
    try {
        const urlObj = new URL(targetUrl);
        result.url = urlObj.origin;
        const hostname = urlObj.hostname.toLowerCase();
        const path = urlObj.pathname;
        const lowerPath = path.toLowerCase();
        const idRegex = /\/(?:server|servers|api\/client\/servers|api\/user\/servers)\/([a-z0-9]+)/i;
        const idMatch = path.match(idRegex);
        if (idMatch && idMatch[1]) {
            if (!result.id || result.id.length < 4) {
                result.id = idMatch[1];
            }
        }
        if (!forcedType) {
            if (hostname.includes('altare.sh')) {
                result.type = 'altare';
                result.autoAfk = true;
                const tenantMatch = path.match(/\/api\/tenants\/([a-f0-9-]+)/i) || path.match(/\/tenant\/([a-f0-9-]+)/i);
                if (tenantMatch && tenantMatch[1]) {
                    if (!result.id) result.id = tenantMatch[1];
                }
            }
            else if (hostname.includes('hyper-hub.nl') || hostname.includes('hyperactyl')) {
                result.type = 'hyperactyl';
                result.path = '/ws';
                result.balancePath = '/wallet/balance';
                result.autoAfk = true;
            }
            else {
                const featherDomains = FEATHERPANEL_DOMAINS;
                const isFeatherDomain = featherDomains.some(d => hostname.includes(d));
                if (isFeatherDomain) {
                    result.type = 'featherpanel';
                    result.path = '/api/user/billingafk/status';
                }
                else if (hostname.includes('overnode.fr') || hostname.includes('heliactyl')) {
                    result.type = 'heliactyl';
                    result.path = '/api/afk/ws';
                    result.autoAfk = true;
                }
                else if (lowerPath.includes('billingafk')) {
                    result.type = 'featherpanel';
                    result.path = '/api/user/billingafk/status';
                    result.autoAfk = true;
                }
                else if (lowerPath.includes('/api/afk/ws') || lowerPath.includes('wallet/balance')) {
                    result.type = 'heliactyl';
                    result.path = '/api/afk/ws';
                    result.autoAfk = true;
                }
                else if (lowerPath.endsWith('/afk') || lowerPath.includes('/earn/afk') || lowerPath.includes('/dashboard/afk')) {
                    result.type = 'featherpanel';
                    result.path = '/api/user/billingafk/status';
                    result.autoAfk = true;
                }
                else if (lowerPath.includes('/earn') || lowerPath.includes('/store') || lowerPath.includes('/credits')) {
                    result.type = 'jexactyl';
                    result.path = '/api/client/store/earn';
                    result.autoAfk = true;
                }
                else if (lowerPath.includes('/billing') || hostname.includes('pelican')) {
                    result.type = 'pelican';
                }
            }
        }
        if (hostname.includes('lemonhost.me') && !result.id) {
            const urlParams = new URLSearchParams(urlObj.search);
            if (urlParams.has('id')) result.id = urlParams.get('id');
        }
    } catch (e) {
    }
    return result;
}
app.post("/api/bots/:id/pto-config", requireAuth, async (req, res) => {
    try {
        const b = activeBots.get(req.params.id);
        if (!b) return res.status(404).json({ success: false, message: "机器人不存在" });
        const rawKey = (req.body.key || "").trim();
        const keyLower = rawKey.toLowerCase();
        const manualType = req.body.type;
        let detectedType = 'pterodactyl';
        let keyTypeLabel = "未知格式";
        let skipDetection = false;
        if (manualType === 'domain') {
            b.pushLog(`🧠 域名模式已启用，正在智能解析...`, 'text-purple-400 font-bold');
            const parsed = smartParsePterodactylUrl(req.body.url, req.body.id, rawKey);
            detectedType = parsed.type;
            keyTypeLabel = "域名自动识别";
            skipDetection = true;
            if (parsed.id && parsed.id !== req.body.id) {
                b.pushLog(`🆔 自动提取 ID: ${parsed.id}`, 'text-cyan-400 text-[10px]');
                req.body.id = parsed.id;
            }
            b.pushLog(`✅ 域名解析完成: ${detectedType}`, 'text-emerald-400 font-bold');
        }
        else if (keyLower.startsWith('fp_')) {
            detectedType = 'featherpanel';
            keyTypeLabel = "FeatherPanel API Key";
            skipDetection = true;
            b.pushLog(`🔑 检测到 fp_ 前缀，强制锁定为 FeatherPanel`, 'text-blue-400 font-bold');
        }
        else if (keyLower.startsWith('ptlc')) {
            detectedType = 'pterodactyl';
            keyTypeLabel = "Pterodactyl Client Key";
            skipDetection = true;
            b.pushLog(`🔑 检测到 ptlc 前缀，强制锁定为 Pterodactyl`, 'text-blue-400 font-bold');
        }
        else {
            keyTypeLabel = rawKey.includes('=') ? "Cookie 字符串" :
                           rawKey.includes('authtoken') ? "AuthToken (Cookie值)" : "通用 Bearer Token";
        }
        const parsed = smartParsePterodactylUrl(req.body.url, req.body.id, rawKey);
        const safeUrl = normalizeUrl(parsed.url);
        if (!skipDetection && parsed.type && parsed.type !== 'pterodactyl' && detectedType === 'pterodactyl') {
            detectedType = parsed.type;
            b.pushLog(`🌐 域名识别: ${parsed.type}`, 'text-cyan-400 text-[10px]');
        }
        const isAuthTokenCookie = rawKey.includes('authtoken') || rawKey.includes('remember_token');
        if (!skipDetection && (rawKey.includes('=') || isAuthTokenCookie)) {
            if (detectedType === 'pterodactyl') {
                // ★ 优先探测 Heliactyl（/api/afk/ws 是其独有端点）
                const probeHeaders = buildPanelHeaders(rawKey, {
                    'User-Agent': COMMON_BROWSER_UA,
                    'Content-Type': 'application/json'
                });
                let isHeliactyl = false;
                try {
                    const hRes = await axios.get(`${safeUrl}/api/afk/ws`, {
                        headers: probeHeaders,
                        timeout: 5000,
                        validateStatus: () => true
                    });
                    // 426 (Upgrade Required) / 200 / 401 / 419 都说明端点存在
                    if (hRes.status !== 404 && hRes.status !== 405) {
                        isHeliactyl = true;
                    }
                } catch(e) {}
                if (isHeliactyl) {
                    detectedType = 'heliactyl';
                    b.pushLog(`💡 检测到 Cookie，识别为 Heliactyl 模式`, 'text-cyan-400');
                } else {
                    detectedType = 'featherpanel';
                    b.pushLog(`💡 检测到 Cookie/AuthToken，推测为 FeatherPanel 模式`, 'text-cyan-400');
                }
            } else if (detectedType === 'heliactyl') {
                b.pushLog(`💡 检测到 Cookie，面板类型: Heliactyl`, 'text-cyan-400');
            }
        }
        if (!skipDetection && detectedType === 'pterodactyl') {
            const headers = buildPanelHeaders(rawKey, {
                'User-Agent': COMMON_BROWSER_UA,
                'Content-Type': 'application/json'
            });
            try {
                const fpRes = await axios.get(`${safeUrl}/api/user/servers`, {
                    headers,
                    timeout: 5000
                });
                if (fpRes.status === 200 && fpRes.data) {
                    detectedType = 'featherpanel';
                    b.pushLog(`✅ 探测成功: FeatherPanel 专用模式`, 'text-emerald-400');
                    if (!parsed.id && fpRes.data.data?.length > 0) {
                        const firstServer = fpRes.data.data[0];
                        parsed.id = firstServer.attributes?.identifier || firstServer.identifier;
                    }
                }
            } catch (e) {}
            if (detectedType === 'pterodactyl') {
                try {
                    const pteroRes = await axios.get(`${safeUrl}/api/client`, {
                        headers,
                        timeout: 5000
                    });
                    if (pteroRes.status === 200 && pteroRes.data) {
                        detectedType = 'pterodactyl';
                        b.pushLog(`✅ 探测成功: Pterodactyl 标准模式`, 'text-emerald-400');
                        if (!parsed.id && pteroRes.data.data?.length > 0) {
                            const firstServer = pteroRes.data.data[0];
                            parsed.id = firstServer.attributes?.identifier || firstServer.identifier;
                        }
                    }
                } catch (e) {}
            }
        }
        if (!detectedType) {
            detectedType = keyLower.startsWith('fp_') ? 'featherpanel' : 'pterodactyl';
            b.pushLog(`⚠️ 探测失败，使用预设类型: ${detectedType}`, 'text-yellow-400');
        }
        const VALID_PANEL_TYPES = ['pterodactyl', 'featherpanel', 'heliactyl', 'altare', 'hyperactyl', 'jexactyl', 'pelican', 'mythicaldash'];
        let finalManualType = "";
        let finalType = detectedType;
        // ★ 先来后到原则：智能保存就是用检测到的类型，清空手动选择
        if (manualType === 'domain') {
            finalManualType = detectedType || "";
            finalType = detectedType;
        } else if (manualType && VALID_PANEL_TYPES.includes(manualType)) {
            finalManualType = manualType;
            finalType = manualType;
        } else {
            finalManualType = "";
            finalType = detectedType;
        }
        const PANEL_API_MAP = {
            'pterodactyl':  { path: '', balancePath: '', autoAfk: false },
            'featherpanel': { path: '/api/user/billingafk/status', balancePath: '/api/user/billingafk/status', autoAfk: true },
            'heliactyl':    { path: '/api/afk/ws', balancePath: '/wallet/balance', autoAfk: true },
            'altare':       { path: '', balancePath: '', autoAfk: true },
            'hyperactyl':   { path: '/ws', balancePath: '/wallet/balance', autoAfk: true },
            'jexactyl':     { path: '/api/client/store/earn', balancePath: '/api/client/store/earn', autoAfk: true },
            'pelican':      { path: '', balancePath: '', autoAfk: false },
            'mythicaldash': { path: '/api/user/session', balancePath: '/api/user/session', autoAfk: true }
        };
        const apiInfo = PANEL_API_MAP[finalType] || PANEL_API_MAP['pterodactyl'];
        b.settings.pterodactyl = {
            url: safeUrl,
            id: parsed.id || req.body.id,
            key: rawKey,
            type: finalType,
            manualType: finalManualType,
            path: apiInfo.path,
            balancePath: apiInfo.balancePath,
            autoAfk: apiInfo.autoAfk
        };
        const typeLabel = finalType === 'altare' ? 'Altare (域名模式)' :
                          finalType === 'featherpanel' ? 'FeatherPanel (专用模式)' :
                          finalType === 'heliactyl' ? 'Heliactyl (WebSocket 模式)' :
                          finalType === 'hyperactyl' ? 'Hyperactyl (域名模式)' :
                          finalType === 'jexactyl' ? 'Jexactyl (积分模式)' :
                          finalType === 'pelican' ? 'Pelican (标准模式)' :
                          'Pterodactyl (标准模式)';
        b.pushLog(`🛡️ 面板配置已更新`, 'text-cyan-400 font-bold');
        b.pushLog(`🔑 认证方式: ${keyTypeLabel}`, 'text-slate-400 text-[10px]');
        b.pushLog(`🖥️ 面板类型: ${typeLabel}`, 'text-emerald-400 text-[10px]');
        if (b.settings.pterodactyl.id) {
            b.pushLog(`🆔 服务器 ID: ${b.settings.pterodactyl.id}`, 'text-slate-400 text-[10px]');
        }
        await saveBotsConfig();
        res.json({
            success: true,
            data: b.settings.pterodactyl
        });
    } catch (err) {
        res.status(500).json({ success: false, message: "服务器内部错误" });
    }
});
