app.post("/api/bots/:id/force-panel-type", requireAuth, async (req, res) => {
    try {
        const b = activeBots.get(req.params.id);
        if (!b) return res.status(404).json({ success: false, message: "机器人不存在" });
        const { type } = req.body;
        if (!b.settings.pterodactyl) b.settings.pterodactyl = {};
        const validTypes = ['pterodactyl', 'featherpanel', 'heliactyl', 'altare', 'hyperactyl', 'jexactyl', 'pelican', 'mythicaldash'];
        const PANEL_API_MAP = {
            'pterodactyl':  { path: '', balancePath: '', autoAfk: false },
            'featherpanel': { path: '/api/user/billingafk/status', balancePath: '/api/user/billingafk/status', autoAfk: true },
            'heliactyl':    { path: '/api/afk/ws', balancePath: '/wallet/balance', autoAfk: true },
            'altare':       { path: '', balancePath: '', autoAfk: true },
            'hyperactyl':   { path: '/ws', balancePath: '/wallet/balance', autoAfk: true },
            'jexactyl':     { path: '/api/client/store/earn', balancePath: '/api/client/store/earn', autoAfk: true },
            'pelican':      { path: '', balancePath: '', autoAfk: false },
            'mythicaldash': { path: '/api/user/session', balancePath: '/api/user/session', autoAfk: true }
        };
        if (!type) {
            b.settings.pterodactyl.manualType = "";
            if (b.settings.pterodactyl.url && b.settings.pterodactyl.key) {
                const parsed = smartParsePterodactylUrl(
                    b.settings.pterodactyl.url,
                    b.settings.pterodactyl.id,
                    b.settings.pterodactyl.key
                );
                b.settings.pterodactyl.type = parsed.type || 'pterodactyl';
                const apiInfo = PANEL_API_MAP[parsed.type] || PANEL_API_MAP['pterodactyl'];
                b.settings.pterodactyl.path = apiInfo.path;
                b.settings.pterodactyl.balancePath = apiInfo.balancePath;
                b.settings.pterodactyl.autoAfk = apiInfo.autoAfk;
                b.pushLog(`🔄 面板类型已切换为自动适配，检测为: ${parsed.type || 'pterodactyl'}`, 'text-slate-400 font-bold');
            } else {
                b.pushLog(`🔄 面板类型已切换为自动适配`, 'text-slate-400 font-bold');
            }
        } else {
            if (!validTypes.includes(type)) {
                return res.status(400).json({ success: false, message: "无效的面板类型" });
            }
            b.settings.pterodactyl.manualType = type;
            b.settings.pterodactyl.type = type;
            const apiInfo = PANEL_API_MAP[type] || PANEL_API_MAP['pterodactyl'];
            b.settings.pterodactyl.path = apiInfo.path;
            b.settings.pterodactyl.balancePath = apiInfo.balancePath;
            b.settings.pterodactyl.autoAfk = apiInfo.autoAfk;
            b.pushLog(`🔧 已手动锁定面板类型: ${type}`, 'text-blue-400 font-bold');
            if (apiInfo.autoAfk) {
                b.pushLog(`💡 该面板支持积分挂机 (路径: ${apiInfo.path || '自动检测'})`, 'text-cyan-400 text-[10px]');
            }
            if (apiInfo.path) {
                b.pushLog(`📂 API 路径已同步: ${apiInfo.path}`, 'text-emerald-400 text-[10px]');
            }
        }
        await saveBotsConfig();
        res.json({ success: true, type: type });
    } catch (err) {
        res.status(500).json({ success: false, message: err.message });
    }
});
