let firefoxProcess = null;
let tunnelProcess = null;
function firefoxSafeKill(proc, onDone, timeout = 5000) {
    if (!proc) return onDone?.();
    if (proc.exitCode !== null) return onDone?.();
    let called = false;
    const done = () => {
        if (called) return;
        called = true;
        clearTimeout(timer);
        clearTimeout(killTimer);
        onDone?.();
    };
    proc.once('exit', done);
    const timer = setTimeout(done, timeout);
    const killTree = (signal) => {
        if (!proc || proc.exitCode !== null) return;
        if (process.platform === 'win32') {
            try {
                execSync(`taskkill /pid ${proc.pid} /T /F`, { stdio: 'ignore' });
            } catch (e) {
            }
        } else {
            try {
                process.kill(-proc.pid, signal);
            } catch (e) {
                try { proc.kill(signal); } catch (e2) {}
            }
        }
    };
    try {
        killTree('SIGTERM');
    } catch (e) {
        try { killTree('SIGKILL'); } catch (e2) {}
        done();
        return;
    }
    const killTimer = setTimeout(() => {
        if (!called) {
            try { killTree('SIGKILL'); } catch (e) {}
        }
    }, 1500);
}
