    const tunnelRegex = /https:\/\/[a-zA-Z0-9-]+\.trycloudflare\.com/;
    let hasPrintedTunnel = false;
    newTunnel.stderr.on('data', (data) => {
        const text = data.toString();
        const lines = text.split('\n').filter(line => {
            const t = line.trim();
            if (!t) return false;
            if (/https:\/\/[a-zA-Z0-9-]+\.trycloudflare\.com/.test(t)) return true;
            if (/registered domain/i.test(t)) return true;
            if (/error|ERR|warn|fatal/i.test(t)) return true;
            if (/Connection|connection|registered|Registered/i.test(t)) return true;
            if (/^INF\s+/i.test(t)) return false;
            if (t.length <= 120) return true;
            return false;
        });
        if (lines.length > 0) {
            fsSync.appendFileSync(FIREFOX_LOG_FILE, lines.map(l => `[Tunnel] ${l}`).join('\n') + '\n');
        }
        const match = text.match(tunnelRegex);
        if (match && !hasPrintedTunnel) {
            hasPrintedTunnel = true;
            fsSync.appendFileSync(FIREFOX_LOG_FILE, `[System] ✅ 临时隧道已就绪: ${match[0]}\n`);
        }
    });
