app.post('/api/sshx/control', requireAuth, async function(req, res) {
    try {
        var action = req.body.action;
        if (action === 'start') {
            if (sshxProcess) {
                return res.json({ success: false, message: 'SSHX 已在运行中' });
            }
            try { fsSync.writeFileSync(SSHX_LOG_FILE, '--- SSHX Service Start ---\n'); } catch(e) {}
            var result = await startSshxService();
            if (result.code === 0) {
                res.json({ success: true });
            } else {
                res.json({ success: false, message: result.message || '启动失败，请查看日志' });
            }
        }
        else if (action === 'stop') {
            stopSshxService();
            res.json({ success: true });
        }
        else if (action === 'uninstall') {
            stopSshxService();
            if (fsSync.existsSync(SSHX_DIR)) {
                try { fsSync.rmSync(SSHX_DIR, { recursive: true, force: true }); } catch(e) {}
            }
ensureDir(SSHX_DIR);
            sshxConnectUrl = '';
            res.json({ success: true, message: 'SSHX 已完全卸载' });
        }
        else {
            res.status(400).json({ success: false, message: '无效的操作' });
        }
    } catch (err) {
        res.status(500).json({ success: false, message: err.message });
    }
});
app.post('/api/sshx/execute', requireAuth, function(req, res) {
    try {
        var command = req.body.command;
        if (!command || typeof command !== 'string') {
            return res.json({ success: false, message: '命令不能为空' });
        }
        if (!sshxProcess || !sshxProcess.stdin || sshxProcess.stdin.destroyed) {
            return res.json({ success: false, message: 'SSHX 未运行，请先启动' });
        }
        fsSync.appendFileSync(SSHX_LOG_FILE, `$ ${command}\n`);
        sshxProcess.stdin.write(command + '\n');
        res.json({ success: true });
    } catch (err) {
        fsSync.appendFileSync(SSHX_LOG_FILE, `[Error] 命令执行失败: ${err.message}\n`);
        res.json({ success: false, message: err.message });
    }
});
function parseCodeServerLogs() {
    let logs = '暂无日志';
    let tempTunnel = '';
    let fixedTunnel = '';
    let running = false;
    try {
        if (fsSync.existsSync(CODE_SERVER_LOG_FILE)) {
            logs = fsSync.readFileSync(CODE_SERVER_LOG_FILE, 'utf8').trim() || '暂无日志';
        }
    } catch(e) { logs = '读取日志失败'; }
    try {
        let configData = {};
        if (fsSync.existsSync(CODE_SERVER_CONFIG_FILE)) {
            configData = readJsonConfig(CODE_SERVER_CONFIG_FILE, {});
        }
        if (configData.tunnelDomain) {
            fixedTunnel = 'https://' + configData.tunnelDomain;
        }
    } catch(e) {}
    if (codeServerTunnelUrl) tempTunnel = codeServerTunnelUrl;
    running = codeServerProcess !== null && !codeServerProcess.killed;
    return { logs, tempTunnel, fixedTunnel, running };
}

