const BUILD_CENTER_DIR = path.join(AOYOU_APP_DIR, '.build-center');
const BUILD_DECOMPILE_DIR = path.join(BUILD_CENTER_DIR, 'decompile');
const BUILD_ENV_DIR = path.join(BUILD_CENTER_DIR, 'env');
ensureDir(BUILD_DECOMPILE_DIR);
ensureDir(BUILD_ENV_DIR);
function generateDecompileId() {
    return 'dec_' + Date.now().toString(36) + '_' + Math.random().toString(36).substr(2, 6);
}

async function installJDK(version) {
    version = parseInt(version) || 17;
    if (![8, 17, 21].includes(version)) return { success: false, message: '不支持的 JDK 版本，请选择 8、17 或 21' };
    const jdkDir = path.join(BUILD_ENV_DIR, `jdk${version}`);
    const jdkBin = path.join(jdkDir, 'bin', 'java');
    const jdkBinExe = path.join(jdkDir, 'bin', 'java.exe');
    if (fsSync.existsSync(jdkBin) || fsSync.existsSync(jdkBinExe)) {
        return { success: true, message: `JDK ${version} 已安装`, path: jdkDir };
    }
    ensureDir(jdkDir);
    const arch = os.arch() === 'arm64' ? 'aarch64' : 'x64';
    const platform = os.platform();
    let downloadUrl, ext;
    if (platform === 'linux') {
        ext = 'tar.gz';
        downloadUrl = `https://api.adoptium.net/v3/binary/latest/${version}/ga/linux/${arch}/jdk/hotspot/normal/eclipse?project=jdk`;
    } else {
        ext = 'zip';
        downloadUrl = `https://api.adoptium.net/v3/binary/latest/${version}/ga/windows/${arch}/jdk/hotspot/normal/eclipse?project=jdk`;
    }
    try {
        const archivePath = path.join(BUILD_ENV_DIR, `jdk${version}.${ext}`);
        const response = await axios({ method: 'GET', url: downloadUrl, responseType: 'stream', timeout: 300000, maxRedirects: 5 });
        const writer = fsSync.createWriteStream(archivePath);
        await new Promise((resolve, reject) => {
            response.data.pipe(writer);
            writer.on('finish', resolve);
            writer.on('error', reject);
        });
        if (platform === 'linux') {
            execSync(`tar -xzf "${archivePath}" -C "${jdkDir}" --strip-components=1`, { timeout: 120000 });
        } else {
            const AdmZipInst = require('adm-zip');
            const zip = new AdmZipInst(archivePath);
            zip.extractAllTo(BUILD_ENV_DIR, true);
            const entries = fsSync.readdirSync(BUILD_ENV_DIR);
            const extractedName = entries.find(e => e.startsWith(`jdk-${version}`) || e.startsWith(`jdk${version}`));
            if (extractedName && extractedName !== `jdk${version}`) {
                const extractedPath = path.join(BUILD_ENV_DIR, extractedName);
                const targetPath = path.join(BUILD_ENV_DIR, `jdk${version}`);
                try { execSync(`mv "${extractedPath}" "${targetPath}"`, { timeout: 10000 }); } catch(e) {}
            }
        }
        try { await fs.unlink(archivePath); } catch(e) {}
        if (fsSync.existsSync(jdkBin) || fsSync.existsSync(jdkBinExe)) {
            return { success: true, message: `JDK ${version} 安装成功`, path: jdkDir };
        }
        return { success: false, message: `JDK ${version} 安装后未找到 java 可执行文件` };
    } catch (e) {
        return { success: false, message: `JDK ${version} 安装失败: ${e.message}` };
    }
}

async function installDecompiler() {
    const decompilerJar = path.join(BUILD_ENV_DIR, 'vineflower.jar');
    if (fsSync.existsSync(decompilerJar)) {
        const stat = fsSync.statSync(decompilerJar);
        if (stat.size > 1000000) return { success: true, message: 'Vineflower 已安装', path: decompilerJar };
    }
    try {
        const releaseApi = 'https://api.github.com/repos/Vineflower/vineflower/releases/latest';
        const releaseInfo = await axios.get(releaseApi, { timeout: 15000, headers: { 'User-Agent': 'AoyouPanel' } });
        const assets = releaseInfo.data.assets || [];
        const jarAsset = assets.find(a => a.name.endsWith('.jar') && a.name.includes('vineflower'));
        if (!jarAsset) {
            const fallbackUrl = 'https://github.com/Vineflower/vineflower/releases/download/1.10.1/vineflower-1.10.1.jar';
            const response = await axios({ method: 'GET', url: fallbackUrl, responseType: 'arraybuffer', timeout: 120000, maxRedirects: 5 });
            await fs.writeFile(decompilerJar, Buffer.from(response.data));
        } else {
            const response = await axios({ method: 'GET', url: jarAsset.browser_download_url, responseType: 'arraybuffer', timeout: 120000, maxRedirects: 5 });
            await fs.writeFile(decompilerJar, Buffer.from(response.data));
        }
        if (fsSync.existsSync(decompilerJar)) {
            const stat = fsSync.statSync(decompilerJar);
            if (stat.size > 1000000) {
                return { success: true, message: 'Vineflower 安装成功', path: decompilerJar };
            }
        }
        return { success: false, message: 'Vineflower 安装后文件异常' };
    } catch (e) {
        return { success: false, message: `Vineflower 安装失败: ${e.message}` };
    }
}

function getEnvStatus() {
    const result = { jdk17: false, jdk21: false, jdk8: false, decompiler: false, systemJava: false };
    result.jdk17 = fsSync.existsSync(path.join(BUILD_ENV_DIR, 'jdk17', 'bin', 'java')) || fsSync.existsSync(path.join(BUILD_ENV_DIR, 'jdk17', 'bin', 'java.exe'));
    result.jdk21 = fsSync.existsSync(path.join(BUILD_ENV_DIR, 'jdk21', 'bin', 'java')) || fsSync.existsSync(path.join(BUILD_ENV_DIR, 'jdk21', 'bin', 'java.exe'));
    result.jdk8 = fsSync.existsSync(path.join(BUILD_ENV_DIR, 'jdk8', 'bin', 'java')) || fsSync.existsSync(path.join(BUILD_ENV_DIR, 'jdk8', 'bin', 'java.exe'));
    const decJar = path.join(BUILD_ENV_DIR, 'vineflower.jar');
    if (fsSync.existsSync(decJar)) {
        const stat = fsSync.statSync(decJar);
        result.decompiler = stat.size > 1000000;
    }
    try { execSync('java -version 2>&1', { timeout: 3000 }); result.systemJava = true; } catch(e) {}
    return result;
}

async function executeDecompile(jarPath, decompileId) {
    const outputDir = path.join(BUILD_DECOMPILE_DIR, decompileId);
    ensureDir(outputDir);
    const decompilerJar = path.join(BUILD_ENV_DIR, 'vineflower.jar');
    if (!fsSync.existsSync(decompilerJar)) {
        return { success: false, message: '未检测到反编译器，请先在反编译配置中下载安装 Vineflower' };
    }

    const javaExe = (() => {
        const jdk17 = path.join(BUILD_ENV_DIR, 'jdk17', 'bin', 'java');
        const jdk17Exe = path.join(BUILD_ENV_DIR, 'jdk17', 'bin', 'java.exe');
        if (fsSync.existsSync(jdk17)) return jdk17;
        if (fsSync.existsSync(jdk17Exe)) return jdk17Exe;
        try { execSync('java -version 2>&1', { timeout: 3000 }); return 'java'; } catch(e) { return ''; }
    })();
    if (!javaExe) {
        return { success: false, message: '未检测到 Java 环境，请先在反编译配置中下载安装 JDK 17' };
    }

    try {
        execSync(`"${javaExe}" -jar "${decompilerJar}" -dgs=1 -hdc=0 -rbr=1 -asc=1 -udv=1 -rsy=1 "${jarPath}" "${outputDir}"`, {
            timeout: 300000,
            shell: true,
            stdio: ['pipe', 'pipe', 'pipe']
        });
    } catch (e) {
        const hasOutput = fsSync.existsSync(outputDir) && fsSync.readdirSync(outputDir).length > 0;
        if (!hasOutput) {
            return { success: false, message: `反编译失败: ${e.message}` };
        }
    }
    const fileTree = buildFileTree(outputDir);
    return { success: true, decompileId, fileTree, outputDir };
}

function buildFileTree(dir, relativePath = '') {
    const items = [];
    try {
        const entries = fsSync.readdirSync(dir, { withFileTypes: true });
        for (const entry of entries) {
            const entryRelative = relativePath ? `${relativePath}/${entry.name}` : entry.name;
            if (entry.isDirectory()) {
                const children = buildFileTree(path.join(dir, entry.name), entryRelative);
                if (children.length > 0) items.push({ name: entry.name, path: entryRelative, type: 'directory', children });
            } else if (entry.name.endsWith('.java') || entry.name.endsWith('.json') || entry.name.endsWith('.yml') || entry.name.endsWith('.yaml') || entry.name.endsWith('.properties') || entry.name.endsWith('.xml')) {
                items.push({ name: entry.name, path: entryRelative, type: 'file', size: fsSync.statSync(path.join(dir, entry.name)).size });
            }
        }
    } catch (e) {}
    return items.sort((a, b) => { if (a.type !== b.type) return a.type === 'directory' ? -1 : 1; return a.name.localeCompare(b.name); });
}

app.post('/api/build-center/decompile/upload', requireAuth, upload.single('jar'), async function(req, res) {
    try {
        if (!req.file) return res.json({ success: false, message: '未上传文件' });
        const decompileId = generateDecompileId();
        const jarPath = path.join(BUILD_DECOMPILE_DIR, `${decompileId}.jar`);
        await fs.writeFile(jarPath, req.file.buffer);
        const result = await executeDecompile(jarPath, decompileId);
        result.jarName = req.file.originalname;
        res.json(result);
    } catch (e) {
        res.json({ success: false, message: e.message });
    }
});

app.post('/api/build-center/decompile/url', requireAuth, async function(req, res) {
    try {
        const { url, jarName } = req.body;
        if (!url) return res.json({ success: false, message: '请提供 JAR 文件 URL' });
        const decompileId = generateDecompileId();
        const jarPath = path.join(BUILD_DECOMPILE_DIR, `${decompileId}.jar`);
        const response = await axios({ method: 'GET', url, responseType: 'arraybuffer', timeout: 120000, maxRedirects: 5 });
        await fs.writeFile(jarPath, Buffer.from(response.data));
        const result = await executeDecompile(jarPath, decompileId);
        result.jarName = jarName || url.split('/').pop() || 'unknown.jar';
        res.json(result);
    } catch (e) {
        res.json({ success: false, message: e.message });
    }
});

app.get('/api/build-center/decompile/:id/tree', requireAuth, function(req, res) {
    const outputDir = path.join(BUILD_DECOMPILE_DIR, req.params.id);
    if (!fsSync.existsSync(outputDir)) return res.json({ success: false, message: '反编译结果不存在' });
    res.json({ success: true, fileTree: buildFileTree(outputDir) });
});

app.get('/api/build-center/decompile/:id/file', requireAuth, function(req, res) {
    const filePath = path.join(BUILD_DECOMPILE_DIR, req.params.id, req.query.path || '');
    const realBase = path.resolve(BUILD_DECOMPILE_DIR);
    const realPath = path.resolve(filePath);
    if (!realPath.startsWith(realBase)) return res.status(403).json({ success: false, message: '路径非法' });
    if (!fsSync.existsSync(filePath)) return res.json({ success: false, message: '文件不存在' });
    try {
        const content = fsSync.readFileSync(filePath, 'utf8');
        const ext = path.extname(filePath);
        res.json({ success: true, content, language: ext === '.java' ? 'java' : ext === '.xml' ? 'xml' : ext === '.yml' || ext === '.yaml' ? 'yaml' : ext === '.json' ? 'json' : 'text' });
    } catch (e) {
        res.json({ success: false, message: e.message });
    }
});

app.get('/api/build-center/decompile/:id/download', requireAuth, function(req, res) {
    const outputDir = path.join(BUILD_DECOMPILE_DIR, req.params.id);
    if (!fsSync.existsSync(outputDir)) return res.status(404).send('Not found');
    try {
        const zip = new AdmZip();
        zip.addLocalFolder(outputDir);
        const zipBuffer = zip.toBuffer();
        res.setHeader('Content-Type', 'application/zip');
        res.setHeader('Content-Disposition', `attachment; filename="${req.params.id}-sources.zip"`);
        res.send(zipBuffer);
    } catch (e) {
        res.status(500).json({ success: false, message: e.message });
    }
});

app.get('/api/build-center/decompile', requireAuth, function(req, res) {
    const result = [];
    try {
        const entries = fsSync.readdirSync(BUILD_DECOMPILE_DIR, { withFileTypes: true });
        for (const entry of entries) {
            if (entry.isDirectory()) {
                const jarFile = path.join(BUILD_DECOMPILE_DIR, `${entry.name}.jar`);
                if (fsSync.existsSync(jarFile)) {
                    const stat = fsSync.statSync(jarFile);
                    result.push({ decompileId: entry.name, jarSize: stat.size, time: stat.mtime.toISOString() });
                }
            }
        }
    } catch (e) {}
    result.sort((a, b) => new Date(b.time) - new Date(a.time));
    res.json({ success: true, decompiles: result });
});

