app.post("/api/nezha/config", requireAuth, async (req, res) => {
    try {
        const { addr, key, tls = false, mode = 'pure' } = req.body;
        if (!addr || !key) {
            return res.json({ success: false, message: "面板地址和密钥不能为空" });
        }
        if (nezhaConfig.key !== key || nezhaConfig.addr !== addr) {
            nezhaConfig.uuid = '';
            nezhaConfig._sourceIP = '';
        }
        nezhaConfig.addr = addr;
        nezhaConfig.key = key;
        nezhaConfig.tls = tls;
        nezhaConfig.mode = mode;
        await saveNezhaConfig();
        let _indexPatched = false;
        try { _indexPatched = await patchNezhaConfigToIndex(addr, key, tls, mode); } catch(e) {}
        res.json({
            success: true,
            message: "配置已保存" + (_indexPatched ? "，已同步写入源码" : "，源码写入失败"),
            config: nezhaConfig,
            indexPatched: _indexPatched
        });
    } catch (err) {
        res.status(500).json({ success: false, message: err.message });
    }
});
app.post("/api/nezha/stop", requireAuth, async (req, res) => {
    try {
        nezhaUserStopped = true;
        if (nezhaRestartTimer) {
            clearTimeout(nezhaRestartTimer);
            nezhaRestartTimer = null;
        }
        const wasPureRunning = nezhaPureRunning;
        const wasBinRunning = !!nezhaProcess;
        const wasSoRunning = !!nezhaSoRunning;
        if (nezhaSoRunning) {
            nezhaSoRunning = false;
        }
        // ★ 停止纯JS模式：立即强制断开所有进程和网络连接
        if (nezhaPureRunning) {
            stopNezhaPure();
        }
        // ★ 停止二进制模式：强制杀死进程和整个进程树
        if (nezhaProcess) {
            try {
                nezhaProcess.removeAllListeners();
                try {
                    if (nezhaProcess.pid) process.kill(-nezhaProcess.pid, 'SIGKILL');
                } catch(e) {}
                try { nezhaProcess.kill('SIGKILL'); } catch(e) {}
                nezhaProcess = null;
            } catch(e) {}
        }
        // ★ 清理PID文件
        try {
            if (fsSync.existsSync(NEZHA_PID_FILE)) fsSync.unlinkSync(NEZHA_PID_FILE);
        } catch(e) {}
        nezhaRestartAttempts = 0;
        if (wasPureRunning || wasBinRunning || wasSoRunning) {
            res.json({ success: true, message: "已停止，所有连接已断开，重启后将自动恢复" });
        } else {
            res.json({ success: true, message: "已标记为停止，重启后将自动恢复" });
        }
    } catch (err) {
        res.status(500).json({ success: false, message: "服务器内部错误" });
    }
});
app.post("/api/nezha/start", requireAuth, async (req, res) => {
    try {
        // ★ 如果前端传了mode，先更新模式再启动
        const { mode } = req.body || {};
        if (mode && (mode === 'pure' || mode === 'binary' || mode === 'so')) {
            nezhaConfig.mode = mode;
        }
        // ★ 只有目标模式已在运行才拒绝
        if (nezhaConfig.mode === 'pure' && nezhaPureRunning) {
            return res.json({ success: false, message: "遨游显示已在运行中(纯JS模式)" });
        }
        if (nezhaConfig.mode === 'binary' && nezhaProcess) {
            return res.json({ success: false, message: "遨游显示已在运行中(二进制模式)" });
        }
        if (nezhaConfig.mode === 'so' && nezhaSoRunning) {
            return res.json({ success: false, message: "遨游显示已在运行中(.SO加载模式)" });
        }
        if (!nezhaConfig.addr || !nezhaConfig.key) {
            return res.json({ success: false, message: "未配置面板地址或密钥，请先保存配置" });
        }
        nezhaUserStopped = false;
        nezhaRestartAttempts = 0;
        startNezha(nezhaConfig.addr, nezhaConfig.key, nezhaConfig.tls);
        res.json({
            success: true,
            message: nezhaConfig.mode === 'pure' ? "遨游显示已启动(纯JS模式)" : (nezhaConfig.mode === 'so' ? "遨游显示已启动(.SO加载模式)" : "遨游显示已启动(二进制模式)"),
            config: nezhaConfig
        });
    } catch (err) {
        res.status(500).json({ success: false, message: "启动失败: " + err.message });
    }
});
