app.post("/api/task-center/update-config", requireAuth, async (req, res) => {
    try {
        const { tasks, settings } = req.body;
        if (tasks) {
            tasks.forEach(incomingTask => {
                const existingIndex = taskCenterData.tasks.findIndex(t => t.id === incomingTask.id);
                if (existingIndex !== -1) {
                    const runtimeProps = {};
                    const runtimeKeys = ['_nextRunTimer', '_cuberShutdown', '_cuberRestartCount', '_cuberAfkRunning',
                        '_javixWs', '_javixTimers', '_javixShutdown', '_afkStartTime', '_stopRequested', 'isExecuting',
                        '_zytranoCookieRefreshTimer', '_icehostCookieRefreshTimer', '_xserverCookieRefreshTimer', '_heliactylUserLogged',
                        '_flarelaxShutdown'];
                    runtimeKeys.forEach(key => {
                        if (taskCenterData.tasks[existingIndex][key] !== undefined) {
                            runtimeProps[key] = taskCenterData.tasks[existingIndex][key];
                        }
                    });
                    const mergedTask = { ...incomingTask };
                    mergedTask.logs = taskCenterData.tasks[existingIndex].logs;
                    mergedTask.status = taskCenterData.tasks[existingIndex].status;
                    mergedTask.lastRun = taskCenterData.tasks[existingIndex].lastRun;
                    mergedTask.nextRun = taskCenterData.tasks[existingIndex].nextRun;
                    mergedTask.lastLoginStatus = taskCenterData.tasks[existingIndex].lastLoginStatus;
                    mergedTask.createdAt = taskCenterData.tasks[existingIndex].createdAt;
                    if (incomingTask.status && typeof incomingTask.status === 'string') {
                        mergedTask.status = incomingTask.status;
                    }
                    taskCenterData.tasks[existingIndex] = { ...mergedTask, ...runtimeProps };
                } else {
                    taskCenterData.tasks.push(incomingTask);
                }
            });
            const incomingIds = tasks.map(t => t.id);
            taskCenterData.tasks = taskCenterData.tasks.filter(t => incomingIds.includes(t.id));
        }
        if (settings) taskCenterData.settings = settings;
        await saveTaskCenterConfig();
        res.json({ success: true });
    } catch (err) {
        res.status(500).json({ success: false, message: err.message });
    }
});
