app.post("/api/task-center/:taskId/toggle", requireAuth, async (req, res) => {
    try {
        const task = taskCenterData.tasks.find(t => t.id === req.params.taskId);
        if (!task) {
            return res.status(404).json({ success: false, message: '任务不存在' });
        }
        if (task.status === 'stopped') {
            task.status = 'running';
            task.lastRun = new Date().toISOString();
            let interval = task.config.interval;
            if ((!interval || interval <= 0) && task.type === 'renew') {
                interval = 30;
                task.config.interval = 30;
            }
            if (interval && interval > 0) {
                const nextRunTime = new Date(Date.now() + interval * 60000);
                task.nextRun = nextRunTime.toISOString();
            }
            const intervalLabel = interval > 0 ? `，间隔 ${interval} 分钟` : '（未设间隔，仅执行一次）';
            addTaskLog(task.id, `任务 "${task.name}" 已启动${intervalLabel}`, 'success');
            executeTaskLogic(task.id);
        } else {
            task.status = 'stopped';
            task.nextRun = null;
            addTaskLog(task.id, `任务 "${task.name}" 已停止${task._afkStartTime ? ' | 挂机: ' + formatDuration(Math.round((Date.now() - task._afkStartTime) / 60000)) : ''}`, 'warning');
            cleanupTaskRuntime(task);
            addTaskLog(task.id, '✅ 所有后台服务已完全停止', 'success');
        }
        await saveTaskCenterConfig();
        res.json({ success: true, status: task.status });
    } catch (err) {
        res.status(500).json({ success: false, message: err.message });
    }
});
app.delete("/api/task-center/:taskId", requireAuth, async (req, res) => {
    try {
        const index = taskCenterData.tasks.findIndex(t => t.id === req.params.taskId);
        if (index === -1) {
            return res.status(404).json({ success: false, message: '任务不存在' });
        }
        const task = taskCenterData.tasks[index];
        if (task._nextRunTimer) {
            clearTimeout(task._nextRunTimer);
            task._nextRunTimer = null;
        }
        if (task.status === 'running') {
            task.status = 'stopped';
        }
        cleanupTaskRuntime(task);
        task._stopRequested = true;
        task._isBotCardAdapter = null;
        task._logFn = null;
        task._saveFn = null;
        task.isExecuting = false;
        if (task.type === 'referral') {
            const accountsDir = path.join(process.cwd(), 'node_modules', '.referral_accounts');
            const filesToDelete = task.config.referralAccountsFiles || [];
            for (const filePath of filesToDelete) {
                try { if (fsSync.existsSync(filePath)) fsSync.unlinkSync(filePath); } catch(e) {}
            }
            try {
                if (fsSync.existsSync(accountsDir)) {
                    const allFiles = fsSync.readdirSync(accountsDir);
                    for (const f of allFiles) {
                        if (f.startsWith('referral_') && f.endsWith('.json')) {
                            try { fsSync.unlinkSync(path.join(accountsDir, f)); } catch(e) {}
                        }
                    }
                    const remaining = fsSync.readdirSync(accountsDir);
                    if (remaining.length === 0) {
                        try { fsSync.rmdirSync(accountsDir); } catch(e) {}
                    }
                }
            } catch(e) {}
            task.config.referralAccounts = [];
            task.config.referralAccountsFiles = [];
        }
        taskCenterData.tasks.splice(index, 1);
        await saveTaskCenterConfig();
        res.json({ success: true });
    } catch (err) {
        res.status(500).json({ success: false, message: err.message });
    }
});
