// ★ 检查 Cookie 有效期（前端填入 Cookie 后调用，返回剩余时间）
app.post("/api/task-center/check-cookie", requireAuth, async (req, res) => {
    try {
        const { cookie, url } = req.body || {};
        if (!cookie) return res.json({ success: false, message: '未提供 Cookie' });
        const safeCookie = String(cookie).trim();
        if (/puratya/i.test(url || '') || /mrtcloud_token=/.test(safeCookie) || /^eyJ[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+$/.test(safeCookie)) {
            const info = analyzePuratyaCookie(safeCookie);
            if (info.valid) {
                let baseUrl = null;
                try { baseUrl = new URL(url || '').origin; } catch(e) {}
                let serverStatus = null;
                if (baseUrl) {
                    try {
                        const me = await axios.get(`${baseUrl}/api/auth/me`, {
                            headers: {
                                'Cookie': safeCookie.includes('=') ? safeCookie : `mrtcloud_token=${safeCookie}`,
                                'Accept': 'application/json',
                                'User-Agent': COMMON_BROWSER_UA,
                            },
                            timeout: 8000, validateStatus: () => true, httpsAgent: UNSAFE_HTTPS_AGENT,
                        });
                        serverStatus = me.status;
                    } catch(e) { serverStatus = -1; }
                }
                return res.json({
                    success: true,
                    panelType: 'puratya',
                    expired: info.expired,
                    exp: info.exp,
                    expDate: new Date(info.exp * 1000).toLocaleString('zh-CN', { timeZone: 'Asia/Shanghai' }),
                    remainingDays: info.remainingDays,
                    remainingHours: info.remainingHours,
                    serverStatus: serverStatus,
                    message: info.expired ? 'Cookie 已过期' : (serverStatus === 200 ? 'Cookie 有效' : (serverStatus ? `服务端返回 ${serverStatus}` : '无法验证'))
                });
            }
        }
        // ★ Keitocloud: 调 /api/me 验证 Cookie + 解析 session 的 Expires
        if (/keitocloud\.jp/i.test(url || '') || /kc_device_id=/.test(safeCookie)) {
            try {
                let baseUrl = null;
                try { baseUrl = new URL(url || '').origin; } catch(e) {}
                let serverStatus = null;
                let expDate = null;
                let expMs = 0;
                if (baseUrl) {
                    try {
                        const me = await axios.get(`${baseUrl}/api/me`, {
                            headers: {
                                'Cookie': safeCookie,
                                'Accept': '*/*',
                                'User-Agent': COMMON_BROWSER_UA,
                                'Referer': baseUrl + '/dashboard',
                            },
                            timeout: 8000, validateStatus: () => true, httpsAgent: UNSAFE_HTTPS_AGENT,
                        });
                        serverStatus = me.status;
                        // 从 set-cookie 解析新 session 的 Expires
                        if (me.headers['set-cookie']) {
                            const setCookies = Array.isArray(me.headers['set-cookie']) ? me.headers['set-cookie'] : [me.headers['set-cookie']];
                            for (const sc of setCookies) {
                                if (/^session=/.test(sc)) {
                                    const expMatch = sc.match(/Expires=([^;]+)/i);
                                    if (expMatch) {
                                        expMs = new Date(expMatch[1].trim()).getTime();
                                        expDate = new Date(expMs).toLocaleString('zh-CN', { timeZone: 'Asia/Shanghai' });
                                    }
                                }
                            }
                        }
                    } catch(e) { serverStatus = -1; }
                }
                const now = Date.now();
                const remainingMs = expMs ? (expMs - now) : 0;
                const remainingDays = Math.floor(remainingMs / 86400000);
                const remainingHours = Math.floor(remainingMs / 3600000) % 24;
                const expired = expMs > 0 && remainingMs <= 0;
                return res.json({
                    success: true,
                    panelType: 'keitocloud',
                    expired: expired,
                    expDate: expDate || '未知',
                    remainingDays,
                    remainingHours,
                    serverStatus: serverStatus,
                    message: serverStatus === 200
                        ? (expDate ? `Cookie 有效 (session 到期: ${expDate})` : 'Cookie 有效')
                        : (serverStatus ? `服务端返回 ${serverStatus}` : '无法验证')
                });
            } catch(e) {
                return res.json({ success: true, panelType: 'keitocloud', message: '解析失败: ' + e.message });
            }
        }
        return res.json({
            success: true,
            panelType: 'unknown',
            expired: false,
            message: '此面板 Cookie 暂不支持自动解析有效期，需通过运行日志查看状态'
        });
    } catch (err) {
        res.status(500).json({ success: false, message: err.message });
    }
});
