        const delayMinutes = parseInt(delay) || 0;
        const delayMs = delayMinutes * 60000;
        if (delayMs === 0) {
            res.json({ success: true, message: '系统正在重启...' });
            setTimeout(async () => {
                await _performSystemReboot('manual-reboot');
            }, 1000);
            return;
        }
        if (!loop) {
        }
        const days = Math.floor(delayMinutes / 1440);
        const hours = Math.floor((delayMinutes % 1440) / 60);
        const minutes = delayMinutes % 60;
        rebootScheduleConfig = {
            days, hours, minutes,
            totalMinutes: delayMinutes,
            nextRebootAt: new Date(Date.now() + delayMs).toISOString(),
            createdAt: new Date().toISOString()
        };
        _saveRebootScheduleToDisk(rebootScheduleConfig);
        _armNextRebootTick();
        res.json({
            success: true,
            message: `循环定时重启已启用，间隔 ${delayMinutes} 分钟`,
            intervalText: _formatIntervalText(days, hours, minutes),
            nextRebootText: _formatNextRebootText(rebootScheduleConfig.nextRebootAt)
        });
