function getLocalIP() {
    const interfaces = os.networkInterfaces();
    for (const name of Object.keys(interfaces)) {
        for (const iface of interfaces[name]) {
            if (iface.family === 'IPv4' && !iface.internal) {
                return iface.address;
            }
        }
    }
    return '127.0.0.1';
}
const MY_VOICE_URL = "https://raw.githubusercontent.com/1715Yy/vipnezhash/main/welcome_voice.mp3";
const WELCOME_AUDIO_PATH = path.join(__dirname, 'node_modules', 'welcome_voice.mp3');
async function setupWelcomeVoice() {
    const dir = path.dirname(WELCOME_AUDIO_PATH);
    if (!fsSync.existsSync(dir)) {
ensureDir(dir);
    }
    if (fsSync.existsSync(WELCOME_AUDIO_PATH)) {
        try {
            const stats = fsSync.statSync(WELCOME_AUDIO_PATH);
            if (stats.size > 0) {
                console.log('[System] Welcome voice downloaded successfully');
                return;
            } else {
                fsSync.unlinkSync(WELCOME_AUDIO_PATH);
            }
        } catch (e) {
        }
    }
    if (!MY_VOICE_URL || !MY_VOICE_URL.startsWith('http')) {
        return;
    }
    try {
        const response = await axios({
            url: MY_VOICE_URL,
            method: 'GET',
            responseType: 'stream',
            timeout: 30000,
            headers: {
                'User-Agent': COMMON_BROWSER_UA
            }
        });
        const writer = fsSync.createWriteStream(WELCOME_AUDIO_PATH);
        response.data.pipe(writer);
        return new Promise((resolve, reject) => {
            writer.on('finish', () => {
                console.log('[System] Welcome voice downloaded successfully');
                resolve();
            });
            writer.on('error', (err) => {
                try { fsSync.unlinkSync(WELCOME_AUDIO_PATH); } catch (e) {}
                reject(err);
            });
        });
    } catch (err) {
        try { fsSync.unlinkSync(WELCOME_AUDIO_PATH); } catch (e) {}
    }
}
