function trimConfigFiles() {
    const MAX_CONFIG_SIZE = 2 * 1024 * 1024;
    const configFiles = [
        { path: CONFIG_FILE, name: '机器人配置' },
        { path: TASK_CENTER_FILE, name: '任务中心配置' }
    ];
    for (const cfg of configFiles) {
        try {
            if (!fsSync.existsSync(cfg.path)) continue;
            const stat = fsSync.statSync(cfg.path);
            if (stat.size <= MAX_CONFIG_SIZE) continue;
            const raw = fsSync.readFileSync(cfg.path, 'utf8');
            let data;
            try { data = JSON.parse(raw); } catch(e) { continue; }
            let trimmed = false;
            if (Array.isArray(data)) {
                for (const item of data) {
                    if (item.lastSuccessCookie && item.lastSuccessCookie.length > 500) {
                        item.lastSuccessCookie = item.lastSuccessCookie.substring(0, 500);
                        trimmed = true;
                    }
                    if (item.renewCookieBindings && item.renewCookieBindings.length > 3) {
                        item.renewCookieBindings = item.renewCookieBindings.slice(0, 3);
                        trimmed = true;
                    }
                    if (item.settings) {
                        if (item.settings.pterodactyl && item.settings.pterodactyl.cookie && item.settings.pterodactyl.cookie.length > 500) {
                            item.settings.pterodactyl.cookie = item.settings.pterodactyl.cookie.substring(0, 500);
                            trimmed = true;
                        }
                    }
                }
            } else if (data && data.tasks && Array.isArray(data.tasks)) {
                const maxEntries = data.settings?.maxLogEntries || 100;
                for (const task of data.tasks) {
                    if (task.logs && task.logs.length > maxEntries) {
                        task.logs = task.logs.slice(0, maxEntries);
                        trimmed = true;
                    }
                    if (task.logs) {
                        for (const log of task.logs) {
                            if (log.message && log.message.length > 500) {
                                log.message = log.message.substring(0, 500) + '...';
                                trimmed = true;
                            }
                        }
                    }
                }
            }
            if (trimmed) {
                fsSync.writeFileSync(cfg.path, JSON.stringify(data));
            }
        } catch(e) {}
    }
}
